CREATE OR REPLACE FUNCTION public.add_dispatch_row(p_machine_id uuid, p_shelf_code text, p_boonz_product_id uuid, p_quantity numeric, p_action text, p_dispatch_date date, p_source_kind text DEFAULT 'unknown'::text, p_source_warehouse_id uuid DEFAULT NULL::uuid, p_source_machine_id uuid DEFAULT NULL::uuid, p_edit_role text DEFAULT NULL::text, p_reason text DEFAULT NULL::text, p_conductor_session text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role            text;
  v_shelf_id        uuid;
  v_pod_product_id  uuid;
  v_new_id          uuid;
  v_after           jsonb;
  v_src_name        text;
  v_bp_name         text;
BEGIN
  PERFORM set_config('app.via_rpc','true',true);
  PERFORM set_config('app.rpc_name','add_dispatch_row',true);

  SELECT role INTO v_role FROM public.user_profiles WHERE id = auth.uid();
  IF auth.uid() IS NOT NULL AND v_role NOT IN ('field_staff','warehouse','operator_admin','superadmin','manager') THEN
    RAISE EXCEPTION 'forbidden: add_dispatch_row requires field_staff / warehouse / operator_admin';
  END IF;

  IF p_machine_id IS NULL OR p_boonz_product_id IS NULL OR p_quantity IS NULL OR p_quantity <= 0 THEN
    RAISE EXCEPTION 'p_machine_id, p_boonz_product_id, p_quantity (>0) required';
  END IF;
  IF p_action NOT IN ('Refill','Add New','Remove') THEN
    RAISE EXCEPTION 'p_action must be Refill | Add New | Remove (title case)';
  END IF;
  IF p_source_kind NOT IN ('wh','m2m','truck_transfer','unknown') THEN
    RAISE EXCEPTION 'invalid p_source_kind';
  END IF;
  IF p_source_kind = 'wh' AND p_source_warehouse_id IS NULL THEN
    RAISE EXCEPTION 'source_kind=wh requires p_source_warehouse_id';
  END IF;
  IF p_source_kind IN ('m2m','truck_transfer') AND p_source_machine_id IS NULL THEN
    RAISE EXCEPTION 'source_kind=% requires p_source_machine_id', p_source_kind;
  END IF;

  IF p_source_kind = 'm2m' THEN
    IF NOT EXISTS (
      SELECT 1 FROM public.pod_inventory
      WHERE machine_id = p_source_machine_id
        AND boonz_product_id = p_boonz_product_id
        AND status = 'Active' AND current_stock > 0
    ) THEN
      SELECT official_name INTO v_src_name FROM public.machines WHERE machine_id = p_source_machine_id;
      SELECT boonz_product_name INTO v_bp_name FROM public.boonz_products WHERE product_id = p_boonz_product_id;
      RAISE EXCEPTION 'Source machine % does not carry % — no Active pod_inventory > 0. Pick a different source machine or use a warehouse.',
        COALESCE(v_src_name, p_source_machine_id::text),
        COALESCE(v_bp_name, p_boonz_product_id::text);
    END IF;
  END IF;

  SELECT shelf_id INTO v_shelf_id
  FROM public.shelf_configurations
  WHERE machine_id = p_machine_id AND shelf_code = p_shelf_code;
  IF v_shelf_id IS NULL THEN
    RAISE EXCEPTION 'shelf_code % not found on machine %', p_shelf_code, p_machine_id;
  END IF;

  -- >>> FIX D START — resolve pod from the SHELF BINDING, not the mapping default <<<
  -- Primary: the pod the shelf is currently bound to (slot_lifecycle is_current),
  -- accepted only if that pod carries this boonz SKU via an Active product_mapping.
  SELECT sl.pod_product_id INTO v_pod_product_id
  FROM public.slot_lifecycle sl
  WHERE sl.machine_id = p_machine_id
    AND sl.shelf_id   = v_shelf_id
    AND sl.is_current = true
    AND sl.archived   = false
    AND EXISTS (
      SELECT 1 FROM public.product_mapping pm2
      WHERE pm2.pod_product_id   = sl.pod_product_id
        AND pm2.boonz_product_id = p_boonz_product_id
        AND pm2.status = 'Active'
    )
  ORDER BY sl.rotated_in_at DESC NULLS LAST
  LIMIT 1;

  -- Fallback: no current shelf binding that carries this SKU (brand-new shelf, or
  -- Add New before the pod rotates in) -> original product_mapping resolution.
  IF v_pod_product_id IS NULL THEN
    SELECT pm.pod_product_id INTO v_pod_product_id
    FROM public.product_mapping pm
    WHERE pm.boonz_product_id = p_boonz_product_id AND pm.status = 'Active'
      AND (pm.machine_id = p_machine_id OR pm.machine_id IS NULL)
    ORDER BY (pm.machine_id = p_machine_id) DESC NULLS LAST, pm.is_global_default DESC
    LIMIT 1;
  END IF;

  IF v_pod_product_id IS NULL THEN
    RAISE EXCEPTION 'no Active product_mapping for boonz_product % on machine %', p_boonz_product_id, p_machine_id;
  END IF;
  -- >>> FIX D END <<<

  INSERT INTO public.refill_dispatching
    (machine_id, shelf_id, pod_product_id, boonz_product_id, dispatch_date, action,
     quantity, packed, dispatched, picked_up, returned, item_added, include,
     source_kind, source_warehouse_id, source_machine_id, is_m2m, created_by_edit,
     last_edited_by, last_edited_by_role, last_edited_at, edit_count)
  VALUES
    (p_machine_id, v_shelf_id, v_pod_product_id, p_boonz_product_id, p_dispatch_date, p_action,
     p_quantity, false, false, false, false, false, true,
     p_source_kind, p_source_warehouse_id, p_source_machine_id, (p_source_kind IN ('m2m','truck_transfer')), true,
     auth.uid(), p_edit_role, now(), 0)
  RETURNING dispatch_id INTO v_new_id;

  v_after := jsonb_build_object(
    'dispatch_id', v_new_id, 'machine_id', p_machine_id, 'shelf_id', v_shelf_id,
    'boonz_product_id', p_boonz_product_id, 'pod_product_id', v_pod_product_id,
    'quantity', p_quantity, 'action', p_action, 'source_kind', p_source_kind,
    'source_warehouse_id', p_source_warehouse_id, 'source_machine_id', p_source_machine_id);

  INSERT INTO public.refill_dispatching_edit_log
    (dispatch_id, edited_by, edited_by_role, edit_kind, before_state, after_state, reason, conductor_session)
  VALUES
    (v_new_id, auth.uid(), p_edit_role, 'add', NULL, v_after, p_reason, p_conductor_session);

  RETURN jsonb_build_object('dispatch_id', v_new_id, 'edit_kind','add', 'after', v_after);
END $function$

CREATE OR REPLACE FUNCTION public.adjust_pod_inventory(p_machine_name text, p_snapshot_date date DEFAULT CURRENT_DATE, p_lines jsonb DEFAULT NULL::jsonb, p_reason text DEFAULT 'physical_count_reconciliation'::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role text;
  v_machine_id uuid;
  v_line jsonb;
  v_bpid uuid;
  v_new_qty numeric;
  v_exp date;
  v_batch text;
  v_shelf_code text;
  v_shelf_id uuid;
  v_product_name text;
  v_existing pod_inventory%ROWTYPE;
  v_old_qty numeric;
  v_pod_id uuid;
  v_lines_processed int := 0;
  v_lines_updated int := 0;
  v_lines_inserted int := 0;
  v_lines_zeroed int := 0;
  v_results jsonb := '[]'::jsonb;
BEGIN
  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'adjust_pod_inventory', true);

  SELECT role INTO v_role FROM user_profiles WHERE id = auth.uid();
  IF auth.uid() IS NOT NULL AND (v_role IS NULL OR v_role NOT IN ('warehouse', 'operator_admin', 'superadmin', 'manager')) THEN
    RAISE EXCEPTION 'Unauthorized: role "%" cannot adjust pod inventory', COALESCE(v_role, 'none');
  END IF;

  SELECT machine_id INTO v_machine_id FROM machines WHERE official_name = p_machine_name;
  IF v_machine_id IS NULL THEN
    RAISE EXCEPTION 'Machine "%" not found', p_machine_name;
  END IF;

  IF p_lines IS NULL OR jsonb_array_length(p_lines) = 0 THEN
    RAISE EXCEPTION 'p_lines must be a non-empty JSON array';
  END IF;

  FOR v_line IN SELECT * FROM jsonb_array_elements(p_lines)
  LOOP
    v_bpid       := (v_line->>'boonz_product_id')::uuid;
    v_new_qty    := (v_line->>'new_qty')::numeric;
    v_exp        := (v_line->>'expiration_date')::date;
    v_batch      := v_line->>'batch_id';
    v_shelf_code := v_line->>'shelf_code';

    IF v_bpid IS NULL THEN RAISE EXCEPTION 'boonz_product_id required in every line'; END IF;
    IF v_new_qty IS NULL OR v_new_qty < 0 THEN RAISE EXCEPTION 'new_qty must be >= 0'; END IF;
    IF v_shelf_code IS NULL THEN RAISE EXCEPTION 'shelf_code required in every line'; END IF;

    SELECT boonz_product_name INTO v_product_name
    FROM boonz_products WHERE product_id = v_bpid;
    IF v_product_name IS NULL THEN
      RAISE EXCEPTION 'boonz_product_id % not found', v_bpid;
    END IF;

    SELECT shelf_id INTO v_shelf_id
    FROM shelf_configurations
    WHERE machine_id = v_machine_id AND shelf_code = v_shelf_code;

    SELECT * INTO v_existing FROM pod_inventory
    WHERE machine_id = v_machine_id
      AND boonz_product_id = v_bpid
      AND (shelf_id = v_shelf_id OR (shelf_id IS NULL AND v_shelf_id IS NULL))
      AND (expiration_date = v_exp OR (expiration_date IS NULL AND v_exp IS NULL))
      AND status = 'Active'
    ORDER BY snapshot_at DESC
    LIMIT 1
    FOR UPDATE;

    IF FOUND THEN
      v_old_qty := COALESCE(v_existing.current_stock, 0);
      v_pod_id := v_existing.pod_inventory_id;

      UPDATE pod_inventory
      SET current_stock = v_new_qty,
          estimated_remaining = v_new_qty,
          expiration_date = COALESCE(v_exp, v_existing.expiration_date),
          batch_id = COALESCE(v_batch, v_existing.batch_id),
          snapshot_date = p_snapshot_date,
          snapshot_at = now(),
          status = CASE WHEN v_new_qty = 0 THEN 'Inactive' ELSE 'Active' END
      WHERE pod_inventory_id = v_existing.pod_inventory_id;

      v_lines_updated := v_lines_updated + 1;
      IF v_new_qty = 0 THEN v_lines_zeroed := v_lines_zeroed + 1; END IF;
    ELSE
      v_old_qty := 0;

      INSERT INTO pod_inventory (
        machine_id, shelf_id, boonz_product_id,
        snapshot_date, current_stock, estimated_remaining,
        expiration_date, batch_id, status, snapshot_at
      ) VALUES (
        v_machine_id, v_shelf_id, v_bpid,
        p_snapshot_date, v_new_qty, v_new_qty,
        v_exp, COALESCE(v_batch, format('ADJUST-%s', p_snapshot_date)),
        CASE WHEN v_new_qty = 0 THEN 'Inactive' ELSE 'Active' END,
        now()
      )
      RETURNING pod_inventory_id INTO v_pod_id;

      v_lines_inserted := v_lines_inserted + 1;
    END IF;

    INSERT INTO pod_inventory_audit_log (
      pod_inventory_id, machine_id, shelf_id, boonz_product_id,
      expiration_date, source, operation,
      old_stock, new_stock, delta,
      old_status, new_status, actor,
      reference_id, notes
    ) VALUES (
      v_pod_id, v_machine_id, v_shelf_id, v_bpid,
      v_exp, 'correction',
      CASE WHEN v_old_qty = 0 AND v_new_qty > 0 THEN 'insert' ELSE 'update' END,
      v_old_qty, v_new_qty, v_new_qty - v_old_qty,
      CASE WHEN v_old_qty > 0 THEN 'Active' ELSE NULL END,
      CASE WHEN v_new_qty = 0 THEN 'Inactive' ELSE 'Active' END,
      auth.uid(),
      format('adjust-%s-%s-%s', p_machine_name, v_shelf_code, p_snapshot_date),
      format('%s: %s -> %s on %s/%s — %s', v_product_name, v_old_qty, v_new_qty, p_machine_name, v_shelf_code, p_reason)
    );

    v_lines_processed := v_lines_processed + 1;

    v_results := v_results || jsonb_build_object(
      'shelf_code', v_shelf_code,
      'product', v_product_name,
      'old_qty', v_old_qty,
      'new_qty', v_new_qty,
      'delta', v_new_qty - v_old_qty,
      'pod_inventory_id', v_pod_id,
      'action', CASE WHEN v_old_qty = 0 AND v_new_qty > 0 THEN 'inserted'
                     WHEN v_new_qty = 0 THEN 'zeroed'
                     ELSE 'updated' END
    );
  END LOOP;

  RETURN jsonb_build_object(
    'status', 'ok',
    'machine', p_machine_name,
    'snapshot_date', p_snapshot_date,
    'lines_processed', v_lines_processed,
    'lines_updated', v_lines_updated,
    'lines_inserted', v_lines_inserted,
    'lines_zeroed', v_lines_zeroed,
    'details', v_results
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.adjust_warehouse_stock(p_warehouse_id uuid, p_lines jsonb, p_snapshot_date date DEFAULT CURRENT_DATE, p_reason text DEFAULT 'physical_count_reconciliation'::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller_role text; v_caller_id uuid;
  v_line jsonb; v_boonz_id uuid; v_new_wh numeric; v_new_cs numeric;
  v_exp_date date; v_batch text; v_status_val text; v_wh_inv_id uuid;
  v_new_loc text; v_loc_provided boolean;
  v_old_wh numeric; v_old_cs numeric; v_old_exp date;
  v_old_loc text; v_old_status text;
  v_found boolean;
  v_updated int := 0; v_inserted int := 0; v_unchanged int := 0;
  v_details jsonb := '[]'::jsonb; v_wh_name text;
BEGIN
  PERFORM set_config('app.via_rpc', 'true', true);
  PERFORM set_config('app.rpc_name', 'adjust_warehouse_stock', true);
  PERFORM set_config('app.provenance_reason', 'manual_adjust', true);

  SELECT role INTO v_caller_role FROM user_profiles WHERE id = auth.uid();
  v_caller_id := auth.uid();
  IF v_caller_role IS NULL OR v_caller_role NOT IN ('warehouse','operator_admin','superadmin','manager') THEN
    RAISE EXCEPTION 'adjust_warehouse_stock: forbidden for role %', COALESCE(v_caller_role,'anon');
  END IF;

  SELECT name INTO v_wh_name FROM warehouses WHERE warehouse_id = p_warehouse_id;
  IF v_wh_name IS NULL THEN
    RAISE EXCEPTION 'adjust_warehouse_stock: warehouse % not found', p_warehouse_id;
  END IF;

  IF p_lines IS NULL OR jsonb_array_length(p_lines) = 0 THEN
    RAISE EXCEPTION 'adjust_warehouse_stock: p_lines must be a non-empty array';
  END IF;

  FOR v_line IN SELECT * FROM jsonb_array_elements(p_lines) LOOP
    v_boonz_id   := (v_line->>'boonz_product_id')::uuid;
    v_new_wh     := COALESCE((v_line->>'new_warehouse_stock')::numeric, 0);
    v_new_cs     := COALESCE((v_line->>'new_consumer_stock')::numeric, 0);
    v_exp_date   := (v_line->>'expiration_date')::date;
    v_batch      := v_line->>'batch_id';
    v_status_val := COALESCE(v_line->>'status', 'Active');
    v_wh_inv_id  := (v_line->>'wh_inventory_id')::uuid;
    v_loc_provided := (v_line ? 'wh_location');
    v_new_loc    := v_line->>'wh_location';

    v_found := false;

    IF v_wh_inv_id IS NOT NULL THEN
      SELECT warehouse_stock, consumer_stock, expiration_date, wh_location, status
        INTO v_old_wh, v_old_cs, v_old_exp, v_old_loc, v_old_status
        FROM warehouse_inventory
        WHERE wh_inventory_id = v_wh_inv_id AND warehouse_id = p_warehouse_id;
      IF FOUND THEN v_found := true; END IF;
    ELSE
      SELECT wh_inventory_id, warehouse_stock, consumer_stock, expiration_date, wh_location, status
        INTO v_wh_inv_id, v_old_wh, v_old_cs, v_old_exp, v_old_loc, v_old_status
        FROM warehouse_inventory
        WHERE warehouse_id = p_warehouse_id
          AND boonz_product_id = v_boonz_id
          AND expiration_date IS NOT DISTINCT FROM v_exp_date
        ORDER BY created_at ASC
        LIMIT 1;
      IF FOUND THEN v_found := true; END IF;
    END IF;

    IF v_found THEN
      IF v_old_wh = v_new_wh
         AND COALESCE(v_old_cs,0) = v_new_cs
         AND (v_exp_date IS NULL OR v_old_exp IS NOT DISTINCT FROM v_exp_date)
         AND (NOT v_loc_provided OR v_old_loc IS NOT DISTINCT FROM v_new_loc)
         AND v_old_status IS NOT DISTINCT FROM v_status_val THEN
        v_unchanged := v_unchanged + 1;
        v_details := v_details || jsonb_build_object(
          'boonz_product_id', v_boonz_id,
          'wh_inventory_id',  v_wh_inv_id,
          'action',           'unchanged'
        );
        CONTINUE;
      END IF;

      PERFORM set_config('app.source_event_id', v_wh_inv_id::text, true);

      UPDATE warehouse_inventory
         SET warehouse_stock = v_new_wh,
             consumer_stock  = v_new_cs,
             snapshot_date   = p_snapshot_date,
             expiration_date = COALESCE(v_exp_date, expiration_date),
             batch_id        = COALESCE(v_batch, batch_id),
             status          = v_status_val,
             wh_location     = CASE WHEN v_loc_provided THEN v_new_loc ELSE wh_location END
       WHERE wh_inventory_id = v_wh_inv_id;

      IF v_old_wh IS DISTINCT FROM v_new_wh THEN
        INSERT INTO inventory_audit_log (audit_id, wh_inventory_id, boonz_product_id, adjusted_by, old_qty, new_qty, reason, audited_at)
        VALUES (gen_random_uuid(), v_wh_inv_id, v_boonz_id, v_caller_id, v_old_wh, v_new_wh, p_reason||' [warehouse_stock]', now());
      END IF;
      IF COALESCE(v_old_cs,0) IS DISTINCT FROM v_new_cs THEN
        INSERT INTO inventory_audit_log (audit_id, wh_inventory_id, boonz_product_id, adjusted_by, old_qty, new_qty, reason, audited_at)
        VALUES (gen_random_uuid(), v_wh_inv_id, v_boonz_id, v_caller_id, COALESCE(v_old_cs,0), v_new_cs, p_reason||' [consumer_stock]', now());
      END IF;
      IF v_loc_provided AND v_old_loc IS DISTINCT FROM v_new_loc THEN
        INSERT INTO inventory_audit_log (audit_id, wh_inventory_id, boonz_product_id, adjusted_by, old_qty, new_qty, reason, audited_at)
        VALUES (gen_random_uuid(), v_wh_inv_id, v_boonz_id, v_caller_id, v_new_wh, v_new_wh,
                p_reason||' [wh_location: '||COALESCE(v_old_loc,'(null)')||' -> '||COALESCE(v_new_loc,'(null)')||']', now());
      END IF;
      IF v_old_status IS DISTINCT FROM v_status_val THEN
        INSERT INTO inventory_audit_log (audit_id, wh_inventory_id, boonz_product_id, adjusted_by, old_qty, new_qty, reason, audited_at)
        VALUES (gen_random_uuid(), v_wh_inv_id, v_boonz_id, v_caller_id, v_new_wh, v_new_wh,
                p_reason||' [status: '||COALESCE(v_old_status,'(null)')||' -> '||COALESCE(v_status_val,'(null)')||']', now());
      END IF;
      IF v_exp_date IS NOT NULL AND v_old_exp IS DISTINCT FROM v_exp_date THEN
        INSERT INTO inventory_audit_log (audit_id, wh_inventory_id, boonz_product_id, adjusted_by, old_qty, new_qty, reason, audited_at)
        VALUES (gen_random_uuid(), v_wh_inv_id, v_boonz_id, v_caller_id, v_new_wh, v_new_wh,
                p_reason||' [expiration_date: '||COALESCE(v_old_exp::text,'(null)')||' -> '||COALESCE(v_exp_date::text,'(null)')||']', now());
      END IF;

      v_updated := v_updated + 1;
      v_details := v_details || jsonb_build_object(
        'boonz_product_id', v_boonz_id,
        'wh_inventory_id',  v_wh_inv_id,
        'action',           'updated',
        'old_wh',           v_old_wh,
        'new_wh',           v_new_wh
      );
    ELSE
      v_wh_inv_id := gen_random_uuid();
      PERFORM set_config('app.source_event_id', v_wh_inv_id::text, true);

      INSERT INTO warehouse_inventory (
        wh_inventory_id, boonz_product_id, snapshot_date, warehouse_stock,
        consumer_stock, expiration_date, batch_id, status, warehouse_id,
        wh_location, created_at
      )
      VALUES (
        v_wh_inv_id, v_boonz_id, p_snapshot_date, v_new_wh,
        v_new_cs, v_exp_date, v_batch, v_status_val, p_warehouse_id,
        CASE WHEN v_loc_provided THEN v_new_loc ELSE NULL END, now()
      );

      INSERT INTO inventory_audit_log (audit_id, wh_inventory_id, boonz_product_id, adjusted_by, old_qty, new_qty, reason, audited_at)
      VALUES (gen_random_uuid(), v_wh_inv_id, v_boonz_id, v_caller_id, 0, v_new_wh, p_reason||' [new_row]', now());

      v_inserted := v_inserted + 1;
      v_details := v_details || jsonb_build_object(
        'boonz_product_id', v_boonz_id,
        'wh_inventory_id',  v_wh_inv_id,
        'action',           'inserted',
        'warehouse_stock',  v_new_wh,
        'expiration_date',  v_exp_date
      );
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'status',           'ok',
    'warehouse',        v_wh_name,
    'warehouse_id',     p_warehouse_id,
    'lines_processed',  v_updated + v_inserted + v_unchanged,
    'lines_updated',    v_updated,
    'lines_inserted',   v_inserted,
    'lines_unchanged',  v_unchanged,
    'reason',           p_reason,
    'details',          v_details
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.apply_inventory_correction(p_wh_inventory_id uuid DEFAULT NULL::uuid, p_boonz_product_id uuid DEFAULT NULL::uuid, p_warehouse_id uuid DEFAULT NULL::uuid, p_expiration_date date DEFAULT NULL::date, p_new_warehouse_stock numeric DEFAULT NULL::numeric, p_reason text DEFAULT NULL::text, p_corrected_by uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_row warehouse_inventory%ROWTYPE;
  v_inserted boolean := false;
BEGIN
  IF p_new_warehouse_stock IS NULL OR p_new_warehouse_stock < 0 THEN
    RAISE EXCEPTION 'p_new_warehouse_stock must be >= 0';
  END IF;
  IF COALESCE(p_reason, '') = '' THEN
    RAISE EXCEPTION 'p_reason is required for inventory corrections';
  END IF;

  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'apply_inventory_correction', true);
  PERFORM set_config('app.mutation_reason',
    format('inventory correction by %s: %s',
           COALESCE(p_corrected_by::text, 'cs'), p_reason), true);

  -- Path A: row id provided → direct update
  IF p_wh_inventory_id IS NOT NULL THEN
    SELECT * INTO v_row FROM warehouse_inventory WHERE wh_inventory_id = p_wh_inventory_id FOR UPDATE;
    IF NOT FOUND THEN RAISE EXCEPTION 'wh_inventory_id % not found', p_wh_inventory_id; END IF;
    UPDATE warehouse_inventory
    SET warehouse_stock = p_new_warehouse_stock,
        -- If row was Inactive AND now has stock, re-activate
        status = CASE 
          WHEN p_new_warehouse_stock > 0 AND status IN ('Inactive') THEN 'Active'
          WHEN p_new_warehouse_stock = 0 AND status = 'Active' THEN status -- leave Active, manager will inactivate separately
          ELSE status END,
        -- If we're setting an expiry on a row that didn't have one, allow it
        expiration_date = COALESCE(expiration_date, p_expiration_date)
    WHERE wh_inventory_id = p_wh_inventory_id;

  -- Path B: identify by (product, warehouse, expiry)
  ELSIF p_boonz_product_id IS NOT NULL AND p_warehouse_id IS NOT NULL THEN
    IF p_expiration_date IS NULL THEN
      RAISE EXCEPTION 'p_expiration_date required when correcting by (product, warehouse). Never create NULL-expiry rows.';
    END IF;
    SELECT * INTO v_row FROM warehouse_inventory
    WHERE boonz_product_id = p_boonz_product_id
      AND warehouse_id = p_warehouse_id
      AND expiration_date = p_expiration_date
    ORDER BY (status = 'Active') DESC, created_at DESC
    LIMIT 1 FOR UPDATE;

    IF FOUND THEN
      UPDATE warehouse_inventory
      SET warehouse_stock = p_new_warehouse_stock,
          status = CASE 
            WHEN p_new_warehouse_stock > 0 AND status IN ('Inactive') THEN 'Active'
            ELSE status END
      WHERE wh_inventory_id = v_row.wh_inventory_id;
    ELSE
      INSERT INTO warehouse_inventory
        (boonz_product_id, warehouse_id, warehouse_stock, expiration_date, status,
         batch_id, snapshot_date)
      VALUES
        (p_boonz_product_id, p_warehouse_id, p_new_warehouse_stock, p_expiration_date, 'Active',
         format('CORRECTION-%s', CURRENT_DATE), CURRENT_DATE)
      RETURNING wh_inventory_id INTO v_row.wh_inventory_id;
      v_inserted := true;
    END IF;
  ELSE
    RAISE EXCEPTION 'Provide either p_wh_inventory_id OR (p_boonz_product_id + p_warehouse_id + p_expiration_date)';
  END IF;

  RETURN jsonb_build_object(
    'status', 'corrected',
    'wh_inventory_id', v_row.wh_inventory_id,
    'inserted', v_inserted,
    'new_warehouse_stock', p_new_warehouse_stock,
    'reason', p_reason
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.build_draft_for_confirmed(p_plan_date date DEFAULT resolve_refill_plan_date(), p_repick boolean DEFAULT true)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
 SET statement_timeout TO '1200000'
AS $function$
DECLARE
  v_user_id   uuid;
  v_picked    int;
  v_confirmed int;
  v_included  int;
  v_repicked  boolean := false;
  v_auto_conf jsonb;
  v_add       jsonb;
  v_swap      jsonb;
  v_final     jsonb;
BEGIN
  PERFORM set_config('app.via_rpc', 'true', true);
  PERFORM set_config('app.rpc_name', 'build_draft_for_confirmed', true);

  v_user_id := auth.uid();
  IF v_user_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.user_profiles up
    WHERE up.id = v_user_id AND up.role IN ('operator_admin', 'superadmin')
  ) THEN
    RETURN jsonb_build_object('status', 'error',
      'message', 'unauthorized: requires operator_admin or superadmin');
  END IF;
  IF p_plan_date IS NULL THEN RAISE EXCEPTION 'p_plan_date required'; END IF;

  -- PRD-035 WS-E: Saturday is a delivery day (no refill plan). The Friday-8pm cron resolves tomorrow =
  -- Saturday and must NOT build a plan. Early return before any pick/confirm/engine write.
  IF EXTRACT(DOW FROM p_plan_date) = 6 THEN
    RETURN jsonb_build_object('status', 'skipped_saturday', 'plan_date', p_plan_date,
      'message', 'Saturday is a delivery day; no refill plan is generated (PRD-035 WS-E calendar)');
  END IF;

  IF EXISTS (SELECT 1 FROM public.pod_refill_plan
              WHERE plan_date = p_plan_date AND status IN ('approved','stitched'))
     OR EXISTS (SELECT 1 FROM public.refill_dispatching WHERE dispatch_date = p_plan_date) THEN
    RETURN jsonb_build_object('status', 'refused_live_plan', 'plan_date', p_plan_date,
      'message', 'plan already approved/stitched/dispatched; use edit RPCs');
  END IF;

  IF p_repick THEN
    PERFORM public.pick_machines_for_refill(p_plan_date);
    v_repicked := true;
  END IF;

  v_auto_conf := public.confirm_machines_to_visit(p_plan_date);

  SELECT
    COUNT(*) FILTER (WHERE status = 'picked'),
    COUNT(*) FILTER (WHERE status IN ('picked','cs_added') AND confirmed_at IS NOT NULL),
    COUNT(*) FILTER (WHERE status IN ('picked','cs_added') AND confirmed_at IS NOT NULL AND COALESCE(is_included, true) = true)
  INTO v_picked, v_confirmed, v_included
  FROM public.machines_to_visit
  WHERE plan_date = p_plan_date;

  BEGIN
    PERFORM public._assert_gate_zero(p_plan_date);
  EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('status', 'awaiting_confirmation',
      'plan_date', p_plan_date, 'confirmed', v_confirmed, 'picked', v_picked);
  END;

  IF v_included = 0 THEN
    RETURN jsonb_build_object('status', 'no_included_machines',
      'plan_date', p_plan_date, 'confirmed', v_confirmed);
  END IF;

  v_add   := engine_add_pod(p_plan_date, 14);
  v_swap  := engine_swap_pod(p_plan_date, 2, 0.30, 14);
  v_final := engine_finalize_pod(p_plan_date);

  RETURN jsonb_build_object(
    'status', 'draft_ready',
    'plan_date', p_plan_date,
    'repicked', v_repicked,
    'machines_picked', v_picked,
    'machines_confirmed', v_confirmed,
    'machines_included', v_included,
    'auto_confirmed', v_auto_conf,
    'stage_2a', v_add,
    'stage_2b', v_swap,
    'stage_2c', v_final,
    'coverage', public.check_refill_coverage(p_plan_date)
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.confirm_machine_packed(p_machine_name text, p_dispatch_date date DEFAULT NULL::date, p_packed_by uuid DEFAULT NULL::uuid, p_reason text DEFAULT NULL::text, p_final boolean DEFAULT true)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid(); v_role text; v_machine_id uuid;
  v_date date := COALESCE(p_dispatch_date, (CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Dubai')::date);
  v_unresolved jsonb; v_unresolved_n integer; v_resolved_n integer; v_summary jsonb;
BEGIN
  PERFORM set_config('app.via_rpc','true',true);
  PERFORM set_config('app.rpc_name','confirm_machine_packed',true);
  IF v_uid IS NOT NULL THEN
    SELECT role INTO v_role FROM public.user_profiles WHERE id = v_uid;
    IF v_role IS NULL OR v_role NOT IN ('warehouse','operator_admin','superadmin','manager') THEN
      RAISE EXCEPTION 'confirm_machine_packed: forbidden for role %', COALESCE(v_role,'unknown');
    END IF;
  END IF;
  IF p_reason IS NULL OR length(trim(p_reason)) < 10 THEN
    RAISE EXCEPTION 'confirm_machine_packed: p_reason required (>= 10 chars)';
  END IF;
  PERFORM set_config('app.mutation_reason', p_reason, true);
  SELECT machine_id INTO v_machine_id FROM public.machines WHERE official_name = p_machine_name;
  IF v_machine_id IS NULL THEN RAISE EXCEPTION 'confirm_machine_packed: machine % not found', p_machine_name; END IF;
  SELECT COALESCE(jsonb_agg(jsonb_build_object('dispatch_id', rd.dispatch_id, 'shelf_id', rd.shelf_id,
            'boonz_product_id', rd.boonz_product_id, 'action', rd.action, 'quantity', rd.quantity) ORDER BY rd.shelf_id), '[]'::jsonb),
         COUNT(*) INTO v_unresolved, v_unresolved_n
  FROM public.refill_dispatching rd
  WHERE rd.machine_id = v_machine_id AND rd.dispatch_date = v_date
    AND COALESCE(rd.cancelled, false) = false AND COALESCE(rd.include, true) = true
    AND COALESCE(rd.packed, false) = false AND COALESCE(rd.skipped, false) = false
    AND COALESCE(rd.pack_outcome::text, '') <> 'not_filled' AND rd.action IN ('Refill','Add New','Add');
  SELECT COUNT(*) INTO v_resolved_n FROM public.refill_dispatching rd
  WHERE rd.machine_id = v_machine_id AND rd.dispatch_date = v_date
    AND COALESCE(rd.cancelled, false) = false AND COALESCE(rd.include, true) = true
    AND (rd.packed OR rd.skipped OR rd.pack_outcome = 'not_filled');
  IF p_final AND v_unresolved_n > 0 THEN
    RETURN jsonb_build_object('status','blocked','machine',p_machine_name,'dispatch_date',v_date,
      'unresolved_count',v_unresolved_n,'unresolved',v_unresolved,
      'message','Finish blocked: some included lines are neither packed nor marked not_filled/skipped. Pack/mark them, or use Save & come back.');
  END IF;
  SELECT jsonb_build_object(
    'total_included', COUNT(*) FILTER (WHERE COALESCE(include,true) AND NOT COALESCE(cancelled,false)),
    'packed', COUNT(*) FILTER (WHERE packed AND COALESCE(pack_outcome::text,'packed') NOT IN ('partial','not_filled')),
    'partial', COUNT(*) FILTER (WHERE pack_outcome = 'partial'),
    'not_filled', COUNT(*) FILTER (WHERE pack_outcome = 'not_filled'),
    'skipped', COUNT(*) FILTER (WHERE skipped))
  INTO v_summary FROM public.refill_dispatching
  WHERE machine_id = v_machine_id AND dispatch_date = v_date AND NOT COALESCE(cancelled,false);
  INSERT INTO public.dispatch_pack_confirmation (machine_id, dispatch_date, confirmed_by, confirmed_at, reason, summary, final)
  VALUES (v_machine_id, v_date, COALESCE(p_packed_by, v_uid), now(), p_reason, v_summary, p_final)
  ON CONFLICT (machine_id, dispatch_date) DO UPDATE
    SET confirmed_by = EXCLUDED.confirmed_by, confirmed_at = now(), reason = EXCLUDED.reason,
        summary = EXCLUDED.summary, final = EXCLUDED.final;
  IF p_final THEN
    RETURN jsonb_build_object('status','ok','confirmed',true,'machine',p_machine_name,'dispatch_date',v_date,
      'pack_state','completed','confirmed_by',COALESCE(p_packed_by, v_uid),
      'packed_n',(v_summary->>'packed')::int,'partial_n',(v_summary->>'partial')::int,
      'skipped_n',(v_summary->>'skipped')::int,'not_filled_n',(v_summary->>'not_filled')::int,'summary',v_summary);
  ELSE
    RETURN jsonb_build_object('status','saved','saved',true,'machine',p_machine_name,'dispatch_date',v_date,
      'pack_state','in_progress','resolved_n',v_resolved_n,'remaining_n',v_unresolved_n,'summary',v_summary);
  END IF;
END; $function$

CREATE OR REPLACE FUNCTION public.confirm_stitched_plan(p_plan_date date)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id   uuid;
  v_rows      integer;
BEGIN
  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'confirm_stitched_plan', true);

  v_user_id := auth.uid();
  -- Allow service_role too — Stage 3 Stitch (edge function) will call this
  IF v_user_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.user_profiles up
    WHERE up.id = v_user_id AND up.role = 'operator_admin'
  ) THEN
    RAISE EXCEPTION 'confirm_stitched_plan: caller % lacks operator_admin role', v_user_id;
  END IF;

  IF p_plan_date IS NULL THEN
    RAISE EXCEPTION 'p_plan_date required';
  END IF;

  UPDATE public.pod_refill_plan
     SET status      = 'stitched',
         stitched_at = now(),
         updated_at  = now()
   WHERE plan_date = p_plan_date
     AND status    = 'approved';

  GET DIAGNOSTICS v_rows = ROW_COUNT;

  RETURN jsonb_build_object('plan_date', p_plan_date, 'stitched_rows', v_rows);
END;
$function$

CREATE OR REPLACE FUNCTION public.edit_dispatch_product(p_dispatch_id uuid, p_new_boonz_product_id uuid, p_edit_role text, p_reason text DEFAULT NULL::text, p_conductor_session text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_row     refill_dispatching%ROWTYPE;
  v_role    text;
  v_new_pod uuid;
  v_before  jsonb;
  v_after   jsonb;
BEGIN
  PERFORM set_config('app.via_rpc','true',true);
  PERFORM set_config('app.rpc_name','edit_dispatch_product',true);

  SELECT role INTO v_role FROM public.user_profiles WHERE id = auth.uid();
  IF auth.uid() IS NOT NULL AND v_role NOT IN ('field_staff','operator_admin','superadmin','manager') THEN
    RAISE EXCEPTION 'forbidden: edit_dispatch_product requires field_staff (driver) / operator_admin / superadmin / manager';
  END IF;

  IF p_new_boonz_product_id IS NULL THEN RAISE EXCEPTION 'p_new_boonz_product_id required'; END IF;
  IF p_edit_role NOT IN ('driver','operator_admin','superadmin','manager') THEN
    RAISE EXCEPTION 'edit_dispatch_product only allowed for driver / operator_admin (not WH manager)';
  END IF;

  SELECT * INTO v_row FROM public.refill_dispatching WHERE dispatch_id = p_dispatch_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'dispatch % not found', p_dispatch_id; END IF;
  IF NOT v_row.picked_up THEN RAISE EXCEPTION 'dispatch % not picked up — driver edits blocked', p_dispatch_id; END IF;
  IF v_row.item_added THEN RAISE EXCEPTION 'dispatch % already item_added — edit blocked', p_dispatch_id; END IF;

  -- FIX D2: resolve pod from the SHELF BINDING (slot_lifecycle current pod), not the
  -- product_mapping default. Accept the shelf-bound pod only when it carries the new
  -- boonz SKU via an Active product_mapping, so pod_product_id stays consistent with
  -- boonz_product_id. Fall back to product_mapping (per-machine wins, then global
  -- default) only when the shelf has no current binding that carries this SKU.
  SELECT sl.pod_product_id INTO v_new_pod
  FROM public.slot_lifecycle sl
  WHERE sl.machine_id = v_row.machine_id
    AND sl.shelf_id   = v_row.shelf_id
    AND sl.is_current = true
    AND sl.archived   = false
    AND EXISTS (
      SELECT 1 FROM public.product_mapping pm2
      WHERE pm2.pod_product_id   = sl.pod_product_id
        AND pm2.boonz_product_id = p_new_boonz_product_id
        AND pm2.status = 'Active'
    )
  ORDER BY sl.rotated_in_at DESC NULLS LAST
  LIMIT 1;

  IF v_new_pod IS NULL THEN
    SELECT pm.pod_product_id INTO v_new_pod
    FROM public.product_mapping pm
    WHERE pm.boonz_product_id = p_new_boonz_product_id
      AND pm.status = 'Active'
      AND (pm.machine_id = v_row.machine_id OR pm.machine_id IS NULL)
    ORDER BY (pm.machine_id = v_row.machine_id) DESC NULLS LAST, pm.is_global_default DESC
    LIMIT 1;
  END IF;

  IF v_new_pod IS NULL THEN
    RAISE EXCEPTION 'boonz_product % has no Active product_mapping for machine %', p_new_boonz_product_id, v_row.machine_id;
  END IF;

  v_before := jsonb_build_object('boonz_product_id', v_row.boonz_product_id,
                                 'pod_product_id',   v_row.pod_product_id);

  UPDATE public.refill_dispatching
  SET boonz_product_id          = p_new_boonz_product_id,
      pod_product_id            = v_new_pod,
      original_boonz_product_id = COALESCE(original_boonz_product_id, v_row.boonz_product_id),
      edit_count                = edit_count + 1,
      last_edited_by            = auth.uid(),
      last_edited_by_role       = p_edit_role,
      last_edited_at            = now()
  WHERE dispatch_id = p_dispatch_id;

  v_after := jsonb_build_object('boonz_product_id', p_new_boonz_product_id,
                                'pod_product_id',   v_new_pod);

  INSERT INTO public.refill_dispatching_edit_log
    (dispatch_id, edited_by, edited_by_role, edit_kind, before_state, after_state, reason, conductor_session)
  VALUES
    (p_dispatch_id, auth.uid(), p_edit_role, 'product', v_before, v_after, p_reason, p_conductor_session);

  RETURN jsonb_build_object('dispatch_id', p_dispatch_id, 'edit_kind','product',
                            'before', v_before, 'after', v_after);
END $function$

CREATE OR REPLACE FUNCTION public.edit_dispatch_qty(p_dispatch_id uuid, p_new_qty numeric, p_edit_role text, p_reason text DEFAULT NULL::text, p_conductor_session text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_row    refill_dispatching%ROWTYPE;
  v_role   text;
  v_before jsonb;
  v_after  jsonb;
BEGIN
  PERFORM set_config('app.via_rpc','true',true);
  PERFORM set_config('app.rpc_name','edit_dispatch_qty',true);

  SELECT role INTO v_role FROM public.user_profiles WHERE id = auth.uid();
  IF auth.uid() IS NOT NULL AND v_role NOT IN ('warehouse','operator_admin','superadmin','manager') THEN
    RAISE EXCEPTION 'forbidden: edit_dispatch_qty requires warehouse / operator_admin / superadmin / manager';
  END IF;

  IF p_new_qty IS NULL OR p_new_qty < 0 THEN RAISE EXCEPTION 'invalid p_new_qty'; END IF;
  IF p_edit_role NOT IN ('driver','warehouse_manager','operator_admin','superadmin','manager') THEN
    RAISE EXCEPTION 'invalid p_edit_role';
  END IF;

  SELECT * INTO v_row FROM public.refill_dispatching WHERE dispatch_id = p_dispatch_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'dispatch % not found', p_dispatch_id; END IF;
  IF v_row.item_added THEN
    RAISE EXCEPTION 'dispatch % already item_added — edit blocked', p_dispatch_id;
  END IF;

  v_before := jsonb_build_object('quantity', v_row.quantity);

  UPDATE public.refill_dispatching
  SET quantity            = p_new_qty,
      original_quantity   = COALESCE(original_quantity, v_row.quantity),
      edit_count          = edit_count + 1,
      last_edited_by      = auth.uid(),
      last_edited_by_role = p_edit_role,
      last_edited_at      = now()
  WHERE dispatch_id = p_dispatch_id;

  v_after := jsonb_build_object('quantity', p_new_qty);

  INSERT INTO public.refill_dispatching_edit_log
    (dispatch_id, edited_by, edited_by_role, edit_kind, before_state, after_state, reason, conductor_session)
  VALUES
    (p_dispatch_id, auth.uid(), p_edit_role, 'qty', v_before, v_after, p_reason, p_conductor_session);

  RETURN jsonb_build_object('dispatch_id', p_dispatch_id, 'edit_kind','qty',
                            'before', v_before, 'after', v_after);
END $function$

CREATE OR REPLACE FUNCTION public.pack_dispatch_line(p_dispatch_id uuid, p_picks jsonb, p_packed_by uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_dispatch refill_dispatching%ROWTYPE;
  v_pick jsonb;
  v_wh_row warehouse_inventory%ROWTYPE;
  v_pick_qty numeric;
  v_pick_bpid uuid;
  v_total_picked numeric := 0;
  v_first_pick boolean := true;
  v_new_child_id uuid;
  v_picks_used jsonb := '[]'::jsonb;
  v_today date := (now() AT TIME ZONE 'Asia/Dubai')::date;
  v_wh uuid;
  v_resolved jsonb := '[]'::jsonb;
  v_rebinds jsonb := '[]'::jsonb;
  v_sub_id uuid;
  v_fail_reason text;
  v_ok boolean;
BEGIN
  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'pack_dispatch_line', true);
  PERFORM set_config('app.provenance_reason', 'dispatch_pack', true);
  PERFORM set_config('app.source_event_id', p_dispatch_id::text, true);
  SELECT * INTO v_dispatch FROM refill_dispatching WHERE dispatch_id = p_dispatch_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Dispatch % not found', p_dispatch_id; END IF;
  IF v_dispatch.skipped = true THEN
    RAISE EXCEPTION 'pack_dispatch_line: dispatch % is SKIPPED (skip_reason: %). Skipped lines cannot be packed; un-skip explicitly first.', p_dispatch_id, COALESCE(v_dispatch.skip_reason, 'no reason recorded');
  END IF;
  IF v_dispatch.cancelled = true THEN
    RAISE EXCEPTION 'pack_dispatch_line: dispatch % is CANCELLED (skip_reason: %). Cancelled lines cannot be packed.', p_dispatch_id, COALESCE(v_dispatch.skip_reason, 'no reason recorded');
  END IF;
  IF COALESCE(v_dispatch.include, true) = false THEN
    RAISE EXCEPTION 'pack_dispatch_line: dispatch % is EXCLUDED (include=false, skip_reason: %). Excluded lines cannot be packed.', p_dispatch_id, COALESCE(v_dispatch.skip_reason, 'no reason recorded');
  END IF;
  IF v_dispatch.packed = true THEN RAISE EXCEPTION 'Already packed'; END IF;
  IF v_dispatch.action NOT IN ('Refill','Add New','Add') THEN
    UPDATE refill_dispatching SET packed = true WHERE dispatch_id = p_dispatch_id;
    RETURN jsonb_build_object('status', 'packed_no_pick', 'dispatch_id', p_dispatch_id);
  END IF;
  SELECT COALESCE(SUM((p->>'qty')::numeric), 0) INTO v_total_picked FROM jsonb_array_elements(p_picks) p;
  IF v_total_picked < 1 THEN
    UPDATE refill_dispatching
       SET pack_outcome      = 'not_filled',
           filled_quantity   = 0,
           original_quantity = COALESCE(original_quantity, quantity), not_filled_reason = COALESCE(NULLIF((SELECT p->>'reason' FROM jsonb_array_elements(p_picks) p WHERE NULLIF(p->>'reason','') IS NOT NULL LIMIT 1), ''), 'not filled at pack time'),
           bind_fail_reason  = NULL,
           bind_fail_at      = NULL
     WHERE dispatch_id = p_dispatch_id;
    RETURN jsonb_build_object('status', 'not_filled', 'dispatch_id', p_dispatch_id,
                              'planned_quantity', v_dispatch.quantity, 'filled_quantity', 0,
                              'pack_outcome', 'not_filled');
  END IF;
  IF v_total_picked > v_dispatch.quantity THEN RAISE EXCEPTION 'Pick total (%) exceeds planned quantity (%)', v_total_picked, v_dispatch.quantity; END IF;
  PERFORM set_config('app.mutation_reason', format('B3 pack: dispatch %s picking %s units total (planned %s)', p_dispatch_id, v_total_picked, v_dispatch.quantity), true);

  v_wh := COALESCE(v_dispatch.from_warehouse_id, '4bebef68-9e36-4a5c-9c2c-142f8dbdae85'::uuid);
  FOR v_pick IN SELECT * FROM jsonb_array_elements(p_picks) LOOP
    v_pick_qty := (v_pick->>'qty')::numeric;
    IF v_pick_qty <= 0 THEN CONTINUE; END IF;
    IF NULLIF(v_pick->>'wh_inventory_id', '') IS NULL THEN
      RAISE EXCEPTION 'pack_dispatch_line: every pick must include from_wh_inventory_id (BUG-006 prevention). Dispatch %, pick payload: %',
        p_dispatch_id, v_pick;
    END IF;
    v_pick_bpid := COALESCE((v_pick->>'boonz_product_id')::uuid, v_dispatch.boonz_product_id);

    SELECT * INTO v_wh_row FROM warehouse_inventory
     WHERE wh_inventory_id = (v_pick->>'wh_inventory_id')::uuid FOR UPDATE;
    v_ok := FOUND
        AND v_wh_row.status = 'Active'
        AND NOT COALESCE(v_wh_row.quarantined, false)
        AND (v_wh_row.expiration_date IS NULL OR v_wh_row.expiration_date >= v_today)
        AND (v_wh_row.reserved_for_machine_id IS NULL OR v_wh_row.reserved_for_machine_id = v_dispatch.machine_id)
        AND COALESCE(v_wh_row.warehouse_stock, 0) >= v_pick_qty;

    IF NOT v_ok THEN
      SELECT p.wh_inventory_id INTO v_sub_id
      FROM v_wh_pickable p
      WHERE p.boonz_product_id = v_pick_bpid
        AND p.warehouse_id = v_wh
        AND (p.reserved_for_machine_id IS NULL OR p.reserved_for_machine_id = v_dispatch.machine_id)
        AND COALESCE(p.warehouse_stock, 0) >= v_pick_qty
        AND p.wh_inventory_id <> (v_pick->>'wh_inventory_id')::uuid
      ORDER BY p.expiration_date ASC NULLS LAST, p.warehouse_stock DESC
      LIMIT 1;

      IF v_sub_id IS NOT NULL THEN
        SELECT * INTO v_wh_row FROM warehouse_inventory WHERE wh_inventory_id = v_sub_id FOR UPDATE;
        IF v_wh_row.status = 'Active' AND NOT COALESCE(v_wh_row.quarantined, false)
           AND (v_wh_row.expiration_date IS NULL OR v_wh_row.expiration_date >= v_today)
           AND (v_wh_row.reserved_for_machine_id IS NULL OR v_wh_row.reserved_for_machine_id = v_dispatch.machine_id)
           AND COALESCE(v_wh_row.warehouse_stock, 0) >= v_pick_qty THEN
          v_rebinds := v_rebinds || jsonb_build_object(
            'from', v_pick->>'wh_inventory_id', 'to', v_sub_id, 'qty', v_pick_qty,
            'new_expiry', v_wh_row.expiration_date, 'boonz_product_id', v_pick_bpid);
          v_pick := jsonb_set(v_pick, '{wh_inventory_id}', to_jsonb(v_sub_id::text));
        ELSE
          v_sub_id := NULL;
        END IF;
      END IF;

      IF v_sub_id IS NULL THEN
        SELECT CASE
          WHEN EXISTS (SELECT 1 FROM warehouse_inventory w
                       WHERE w.boonz_product_id = v_pick_bpid AND w.warehouse_id = v_wh
                         AND w.status = 'Active' AND NOT COALESCE(w.quarantined,false)
                         AND (w.expiration_date IS NULL OR w.expiration_date >= v_today)
                         AND COALESCE(w.warehouse_stock,0) >= v_pick_qty
                         AND w.reserved_for_machine_id IS NOT NULL
                         AND w.reserved_for_machine_id <> v_dispatch.machine_id)
            THEN 'pinned_elsewhere'
          WHEN EXISTS (SELECT 1 FROM warehouse_inventory w
                       WHERE w.boonz_product_id = v_pick_bpid AND w.warehouse_id = v_wh
                         AND COALESCE(w.quarantined,false)
                         AND (w.expiration_date IS NULL OR w.expiration_date >= v_today)
                         AND COALESCE(w.warehouse_stock,0) > 0)
            THEN 'quarantined'
          WHEN EXISTS (SELECT 1 FROM warehouse_inventory w
                       WHERE w.boonz_product_id = v_pick_bpid AND w.warehouse_id = v_wh
                         AND w.status <> 'Active' AND NOT COALESCE(w.quarantined,false)
                         AND (w.expiration_date IS NULL OR w.expiration_date >= v_today)
                         AND COALESCE(w.warehouse_stock,0) > 0)
            THEN 'inactive_batch'
          ELSE 'no_stock'
        END INTO v_fail_reason;

        UPDATE refill_dispatching
           SET bind_fail_reason = v_fail_reason, bind_fail_at = now()
         WHERE dispatch_id = p_dispatch_id;
        RETURN jsonb_build_object('status', 'bind_failed', 'dispatch_id', p_dispatch_id,
                                  'bind_fail_reason', v_fail_reason,
                                  'stale_wh_inventory_id', v_pick->>'wh_inventory_id',
                                  'pick_qty', v_pick_qty, 'boonz_product_id', v_pick_bpid,
                                  'planned_quantity', v_dispatch.quantity);
      END IF;
    END IF;

    v_resolved := v_resolved || v_pick;
  END LOOP;

  FOR v_pick IN SELECT * FROM jsonb_array_elements(v_resolved) LOOP
    v_pick_qty := (v_pick->>'qty')::numeric;
    v_pick_bpid := COALESCE((v_pick->>'boonz_product_id')::uuid, v_dispatch.boonz_product_id);
    SELECT * INTO v_wh_row FROM warehouse_inventory WHERE wh_inventory_id = (v_pick->>'wh_inventory_id')::uuid FOR UPDATE;
    IF NOT FOUND THEN RAISE EXCEPTION 'WH row % not found', v_pick->>'wh_inventory_id'; END IF;
    IF COALESCE(v_wh_row.warehouse_stock, 0) < v_pick_qty THEN RAISE EXCEPTION 'WH row % has only % units, cannot pick %', v_wh_row.wh_inventory_id, v_wh_row.warehouse_stock, v_pick_qty; END IF;
    UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) - v_pick_qty, consumer_stock = COALESCE(consumer_stock, 0) + v_pick_qty WHERE wh_inventory_id = v_wh_row.wh_inventory_id;
    IF v_first_pick THEN
      UPDATE refill_dispatching SET packed = false WHERE dispatch_id = p_dispatch_id;
      UPDATE refill_dispatching SET packed = true, expiry_date = v_wh_row.expiration_date, filled_quantity = v_pick_qty, boonz_product_id = v_pick_bpid, quantity = CASE WHEN refill_qa.flag('qty_split_v1')='on' THEN quantity ELSE v_total_picked END, from_wh_inventory_id = v_wh_row.wh_inventory_id, original_quantity = COALESCE(v_dispatch.original_quantity, v_dispatch.quantity), pack_outcome = (CASE WHEN v_total_picked < v_dispatch.quantity THEN 'partial' ELSE 'packed' END)::public.pack_outcome_enum, bind_fail_reason = NULL, bind_fail_at = NULL WHERE dispatch_id = p_dispatch_id;
      v_first_pick := false;
    ELSE
      INSERT INTO refill_dispatching (machine_id, shelf_id, pod_product_id, boonz_product_id, dispatch_date, action, quantity, filled_quantity, include, packed, picked_up, dispatched, returned, item_added, expiry_date, from_wh_inventory_id, pack_outcome) VALUES (v_dispatch.machine_id, v_dispatch.shelf_id, v_dispatch.pod_product_id, v_pick_bpid, v_dispatch.dispatch_date, v_dispatch.action, v_pick_qty, v_pick_qty, true, true, false, false, false, false, v_wh_row.expiration_date, v_wh_row.wh_inventory_id, 'packed') RETURNING dispatch_id INTO v_new_child_id;
    END IF;
    v_picks_used := v_picks_used || jsonb_build_object('wh_inventory_id', v_wh_row.wh_inventory_id, 'batch_id', v_wh_row.batch_id, 'expiry', v_wh_row.expiration_date, 'qty', v_pick_qty, 'boonz_product_id', v_pick_bpid, 'child_dispatch_id', v_new_child_id);
  END LOOP;
  RETURN jsonb_build_object('status', 'packed', 'dispatch_id', p_dispatch_id, 'total_picked', v_total_picked, 'planned_quantity', v_dispatch.quantity, 'pack_outcome', (CASE WHEN v_total_picked < v_dispatch.quantity THEN 'partial' ELSE 'packed' END), 'picks', v_picks_used, 'rebinds', v_rebinds);
END;
$function$

CREATE OR REPLACE FUNCTION public.push_plan_to_dispatch(p_plan_date date, p_machine_name text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id              uuid;
  v_machine_id           uuid;
  v_primary_warehouse_id uuid;
  v_count                int := 0;
  v_skipped              int := 0;
  v_pinned_count         int := 0;
  v_procurement_gaps     int := 0;
  v_preserved            int := 0;
  v_remove_split         int := 0;
  v_leak_n               int := 0;
  line                   RECORD;
  v_batch                RECORD;
  v_leak                 RECORD;
  v_remaining            int;
  v_take                 int;
  v_shelf_id             uuid;
  v_pod_product_id       uuid;
  v_boonz_product_id     uuid;
  v_normalized_shelf     text;
  v_action               text;
  v_dispatch_comment     text;
  v_new_dispatch_id      uuid;
  v_existing_edit_id     uuid;
  v_pinned_wh_id         uuid;
  v_pinned_expiry        date;
  v_pin_eligible         boolean;
  -- PRD-071 WS-B additions
  v_pairing              jsonb := NULL;
  v_prev_via_trigger     text;
  v_prev_mutation_reason text;
  v_transfer_id          uuid;
  v_src_line             RECORD;
  v_src_machine_id       uuid;
  v_src_shelf_id         uuid;
  v_src_normalized_shelf text;
  v_first_remove_id      uuid;
  v_dest_leg_id          uuid;
  v_earliest_expiry      date;
  v_transfer_pairs       int := 0;
  v_transfer_deferred    int := 0;
  v_transfer_skipped     int := 0;
  v_slot_guard           jsonb := NULL;
BEGIN
  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'push_plan_to_dispatch', true);

  v_user_id := auth.uid();
  IF v_user_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.user_profiles
    WHERE id = v_user_id AND role = ANY (ARRAY['operator_admin','superadmin','manager'])
  ) THEN
    RAISE EXCEPTION 'push_plan_to_dispatch: caller % lacks required role', v_user_id;
  END IF;

  IF p_plan_date IS NULL THEN RETURN jsonb_build_object('status','error','error','p_plan_date is required'); END IF;
  IF p_machine_name IS NULL OR length(trim(p_machine_name)) = 0 THEN
    RETURN jsonb_build_object('status','error','error','p_machine_name is required');
  END IF;

  SELECT machine_id, primary_warehouse_id INTO v_machine_id, v_primary_warehouse_id
    FROM machines WHERE official_name = p_machine_name;
  IF v_machine_id IS NULL THEN
    RETURN jsonb_build_object('status','error','error','Machine not found: '||p_machine_name);
  END IF;

  -- drift-kill P1: WEIMI slot guard (block rejects mismatched plan lines here,
  -- before they bridge to dispatching; warn logs to monitoring_alerts)
  v_slot_guard := public.assert_weimi_slot_match(p_plan_date, NULL, p_machine_name);
  PERFORM set_config('app.rpc_name', 'push_plan_to_dispatch', true);

  v_leak_n := 0;
  FOR v_leak IN
    SELECT prp.shelf_id, prp.pod_product_id, prp.action,
           prp.qty::int AS parent, COALESCE(g.children,0)::int AS children
    FROM pod_refill_plan prp
    LEFT JOIN (
      SELECT sc.shelf_id, pp.pod_product_id,
             CASE upper(trim(rpo.action))
               WHEN 'REMOVE' THEN 'REMOVE' WHEN 'MACHINE TO WAREHOUSE' THEN 'M2W' END AS pod_action,
             SUM(rpo.quantity)::int AS children
      FROM refill_plan_output rpo
      JOIN shelf_configurations sc ON sc.machine_id = v_machine_id
           AND sc.shelf_code = regexp_replace(rpo.shelf_code, '^([A-Z])([0-9])$', '\1' || '0' || '\2')
      JOIN pod_products pp ON lower(trim(pp.pod_product_name)) = lower(trim(rpo.pod_product_name))
      WHERE rpo.plan_date = p_plan_date AND rpo.machine_name = p_machine_name
        AND rpo.operator_status = 'approved' AND rpo.dispatched = false
        AND upper(trim(rpo.action)) IN ('REMOVE','MACHINE TO WAREHOUSE')
      GROUP BY sc.shelf_id, pp.pod_product_id, 3
    ) g ON g.shelf_id = prp.shelf_id AND g.pod_product_id = prp.pod_product_id AND g.pod_action = prp.action
    WHERE prp.plan_date = p_plan_date AND prp.machine_id = v_machine_id
      AND prp.action IN ('REMOVE','M2W') AND prp.qty > 0
      AND prp.qty <> COALESCE(g.children, 0)
  LOOP
    INSERT INTO public.stitch_leakage(plan_date, machine_id, shelf_id, pod_product_id,
                                      action, parent_pod_qty, children_sum, delta, detected_by)
    VALUES (p_plan_date, v_machine_id, v_leak.shelf_id, v_leak.pod_product_id,
            v_leak.action, v_leak.parent, v_leak.children, v_leak.parent - v_leak.children,
            'push_plan_to_dispatch');
    v_leak_n := v_leak_n + 1;
  END LOOP;
  IF v_leak_n > 0 THEN
    RETURN jsonb_build_object(
      'status','conservation_violation',
      'machine', p_machine_name,
      'leaking_instructions', v_leak_n,
      'reason','SUM(approved plan children) <> pod_refill_plan qty for REMOVE/M2W — stop-ship; logged durably to stitch_leakage (PRD-053)'
    );
  END IF;

  FOR line IN
    SELECT * FROM refill_plan_output
    WHERE plan_date = p_plan_date AND machine_name = p_machine_name
      AND operator_status = 'approved' AND dispatched = false
  LOOP
    -- PRD-CLEAN-05 v9: prefer the ID columns written by write_refill_plan g8;
    -- fall back to name matching for historical rows where they are NULL.
    v_normalized_shelf := regexp_replace(line.shelf_code, '^([A-Z])([0-9])$', '\1' || '0' || '\2');
    v_shelf_id := line.shelf_id;
    IF v_shelf_id IS NULL THEN
      SELECT shelf_id INTO v_shelf_id FROM shelf_configurations WHERE machine_id=v_machine_id AND shelf_code=v_normalized_shelf;
    END IF;
    v_pod_product_id := line.pod_product_id;
    IF v_pod_product_id IS NULL THEN
      SELECT pod_product_id INTO v_pod_product_id FROM pod_products WHERE lower(trim(pod_product_name))=lower(trim(line.pod_product_name)) LIMIT 1;
    END IF;
    v_boonz_product_id := line.boonz_product_id;
    IF v_boonz_product_id IS NULL THEN
      SELECT product_id INTO v_boonz_product_id FROM boonz_products WHERE lower(trim(boonz_product_name))=lower(trim(line.boonz_product_name)) LIMIT 1;
    END IF;

    IF v_boonz_product_id IS NULL OR v_pod_product_id IS NULL THEN v_skipped := v_skipped + 1; CONTINUE; END IF;

    SELECT rd.dispatch_id INTO v_existing_edit_id
      FROM refill_dispatching rd
     WHERE rd.machine_id     = v_machine_id
       AND rd.dispatch_date  = line.plan_date
       AND rd.shelf_id       = v_shelf_id
       AND rd.pod_product_id = v_pod_product_id
       AND (rd.created_by_edit OR rd.edit_count > 0 OR rd.cancelled OR rd.skipped)
     ORDER BY rd.created_at DESC NULLS LAST
     LIMIT 1;
    IF v_existing_edit_id IS NOT NULL THEN
      UPDATE refill_plan_output SET dispatched = true, dispatch_id = v_existing_edit_id WHERE id = line.id;
      v_preserved := v_preserved + 1;
      CONTINUE;
    END IF;

    v_action := CASE upper(trim(line.action))
      WHEN 'REFILL' THEN 'Refill' WHEN 'ADD NEW' THEN 'Add New'
      WHEN 'REMOVE' THEN 'Remove' WHEN 'MACHINE TO WAREHOUSE' THEN 'Machine To Warehouse'
      WHEN 'SWAP' THEN 'Add New' ELSE trim(line.action)
    END;

    v_dispatch_comment := CASE
      WHEN line.operator_comment IS NOT NULL AND trim(line.operator_comment) != '' THEN
        COALESCE(NULLIF(trim(line.comment), '') || E'\n', '') || E'\U0001F4AC ' || trim(line.operator_comment)
      ELSE line.comment
    END;

    -- PRD-071 WS-B: internal_transfer lines become pre-paired M2M writes.
    -- block_orphan_internal_transfer (PRD-070) forbids unpaired legs, so the
    -- dest line (carries from_machine_id) creates BOTH legs atomically with a
    -- shared m2m_transfer_id; the source Remove line defers to the dest push.
    -- Per-line failures log to monitoring_alerts and never fail the push.
    IF COALESCE(line.source_origin::text,'warehouse') = 'internal_transfer' THEN
      IF v_action IN ('Remove','Machine To Warehouse') THEN
        v_transfer_deferred := v_transfer_deferred + 1;
        CONTINUE;
      END IF;
      IF v_action NOT IN ('Refill','Add New') OR line.from_machine_id IS NULL THEN
        v_transfer_skipped := v_transfer_skipped + 1;
        INSERT INTO public.monitoring_alerts (source, severity, payload)
        VALUES ('m2m_push_unroutable','warning', jsonb_build_object(
          'title', format('M2M line unroutable at push: %s @ %s', line.boonz_product_name, p_machine_name),
          'plan_line_id', line.id, 'plan_date', p_plan_date, 'action', v_action,
          'from_machine_id', line.from_machine_id,
          'detected_by','push_plan_to_dispatch_v7_prd071','detected_at', now()));
        CONTINUE;
      END IF;
      BEGIN
        SELECT rpo.* INTO v_src_line
          FROM refill_plan_output rpo
          JOIN machines sm ON sm.machine_id = line.from_machine_id AND sm.official_name = rpo.machine_name
         WHERE rpo.plan_date = line.plan_date
           AND rpo.source_origin = 'internal_transfer'
           AND upper(trim(rpo.action)) IN ('REMOVE','MACHINE TO WAREHOUSE')
           AND lower(trim(rpo.pod_product_name)) = lower(trim(line.pod_product_name))
           AND rpo.quantity = line.quantity
           AND rpo.operator_status = 'approved' AND rpo.dispatched = false
         ORDER BY rpo.id
         LIMIT 1;
        IF NOT FOUND THEN
          v_transfer_skipped := v_transfer_skipped + 1;
          INSERT INTO public.monitoring_alerts (source, severity, payload)
          VALUES ('m2m_push_no_source_line','warning', jsonb_build_object(
            'title', format('M2M dest line has no matching approved source Remove: %s @ %s', line.boonz_product_name, p_machine_name),
            'plan_line_id', line.id, 'plan_date', p_plan_date, 'qty', line.quantity,
            'from_machine_id', line.from_machine_id,
            'detected_by','push_plan_to_dispatch_v7_prd071','detected_at', now()));
          CONTINUE;
        END IF;

        v_src_machine_id := line.from_machine_id;
        v_src_normalized_shelf := regexp_replace(v_src_line.shelf_code, '^([A-Z])([0-9])$', '\1' || '0' || '\2');
        v_src_shelf_id := v_src_line.shelf_id;
        IF v_src_shelf_id IS NULL THEN
          SELECT shelf_id INTO v_src_shelf_id FROM shelf_configurations
           WHERE machine_id = v_src_machine_id AND shelf_code = v_src_normalized_shelf;
        END IF;

        v_transfer_id := gen_random_uuid();
        v_first_remove_id := NULL;
        v_earliest_expiry := NULL;
        v_remaining := line.quantity;

        FOR v_batch IN
          SELECT pil.expiration_date, pil.current_stock
            FROM public.v_pod_inventory_latest pil
           WHERE pil.machine_id = v_src_machine_id
             AND pil.shelf_id   = v_src_shelf_id
             AND pil.boonz_product_id = v_boonz_product_id
             AND pil.status = 'Active'
             AND COALESCE(pil.current_stock,0) > 0
           ORDER BY pil.expiration_date ASC NULLS LAST
        LOOP
          EXIT WHEN v_remaining <= 0;
          v_take := LEAST(v_batch.current_stock, v_remaining);
          INSERT INTO refill_dispatching (
            machine_id, shelf_id, pod_product_id, boonz_product_id,
            dispatch_date, action, quantity, include, comment,
            from_warehouse_id, from_wh_inventory_id, expiry_date, pinned_at_plan_time,
            source_origin, from_machine_id,
            is_m2m, m2m_transfer_id, source_machine_id, source_kind,
            packed, picked_up, dispatched, returned, item_added
          ) VALUES (
            v_src_machine_id, v_src_shelf_id, v_pod_product_id, v_boonz_product_id,
            line.plan_date, 'Remove', v_take, true,
            COALESCE(NULLIF(trim(v_src_line.comment),''), format('M2M: %s -> %s', v_src_line.machine_name, p_machine_name)),
            NULL, NULL, v_batch.expiration_date, false,
            'internal_transfer'::public.source_origin_enum, NULL,
            true, v_transfer_id, v_src_machine_id, 'm2m',
            true, false, false, false, false
          ) RETURNING dispatch_id INTO v_new_dispatch_id;
          IF v_first_remove_id IS NULL THEN v_first_remove_id := v_new_dispatch_id; END IF;
          IF v_earliest_expiry IS NULL THEN v_earliest_expiry := v_batch.expiration_date; END IF;
          v_remaining := v_remaining - v_take;
          v_count := v_count + 1;
        END LOOP;
        IF v_remaining > 0 THEN
          INSERT INTO refill_dispatching (
            machine_id, shelf_id, pod_product_id, boonz_product_id,
            dispatch_date, action, quantity, include, comment,
            from_warehouse_id, from_wh_inventory_id, expiry_date, pinned_at_plan_time,
            source_origin, from_machine_id,
            is_m2m, m2m_transfer_id, source_machine_id, source_kind,
            packed, picked_up, dispatched, returned, item_added
          ) VALUES (
            v_src_machine_id, v_src_shelf_id, v_pod_product_id, v_boonz_product_id,
            line.plan_date, 'Remove', v_remaining, true,
            format('M2M: %s -> %s', v_src_line.machine_name, p_machine_name) || E'\n' || '[EXPIRY-TO-CONFIRM - remainder not attributable to a known batch (PRD-053)]',
            NULL, NULL, NULL, false,
            'internal_transfer'::public.source_origin_enum, NULL,
            true, v_transfer_id, v_src_machine_id, 'm2m',
            true, false, false, false, false
          ) RETURNING dispatch_id INTO v_new_dispatch_id;
          IF v_first_remove_id IS NULL THEN v_first_remove_id := v_new_dispatch_id; END IF;
          v_count := v_count + 1;
        END IF;

        INSERT INTO refill_dispatching (
          machine_id, shelf_id, pod_product_id, boonz_product_id,
          dispatch_date, action, quantity, include, comment,
          from_warehouse_id, from_wh_inventory_id, expiry_date, pinned_at_plan_time,
          source_origin, from_machine_id,
          is_m2m, m2m_transfer_id, m2m_partner_id, source_machine_id, source_kind,
          packed, picked_up, dispatched, returned, item_added
        ) VALUES (
          v_machine_id, v_shelf_id, v_pod_product_id, v_boonz_product_id,
          line.plan_date, v_action, line.quantity, true,
          COALESCE(NULLIF(trim(v_dispatch_comment),''), format('M2M: %s -> %s', v_src_line.machine_name, p_machine_name)),
          NULL, NULL, v_earliest_expiry, false,
          'internal_transfer'::public.source_origin_enum, v_src_machine_id,
          true, v_transfer_id, v_first_remove_id, v_src_machine_id, 'm2m',
          true, false, false, false, false
        ) RETURNING dispatch_id INTO v_dest_leg_id;

        UPDATE refill_dispatching SET m2m_partner_id = v_dest_leg_id
         WHERE m2m_transfer_id = v_transfer_id AND dispatch_id <> v_dest_leg_id;

        UPDATE refill_plan_output SET dispatched = true, dispatch_id = v_dest_leg_id WHERE id = line.id;
        UPDATE refill_plan_output SET dispatched = true, dispatch_id = v_first_remove_id WHERE id = v_src_line.id;
        v_count := v_count + 1;
        v_transfer_pairs := v_transfer_pairs + 1;
      EXCEPTION WHEN OTHERS THEN
        v_transfer_skipped := v_transfer_skipped + 1;
        INSERT INTO public.monitoring_alerts (source, severity, payload)
        VALUES ('m2m_push_pair_failure','warning', jsonb_build_object(
          'title', format('M2M paired insert failed at push: %s @ %s', line.boonz_product_name, p_machine_name),
          'plan_line_id', line.id, 'plan_date', p_plan_date, 'error', SQLERRM,
          'detected_by','push_plan_to_dispatch_v7_prd071','detected_at', now()));
      END;
      CONTINUE;
    END IF;

    IF v_action IN ('Remove','Machine To Warehouse') THEN
      v_remaining := line.quantity;
      v_new_dispatch_id := NULL;
      FOR v_batch IN
        SELECT pil.expiration_date, pil.current_stock
          FROM public.v_pod_inventory_latest pil
         WHERE pil.machine_id = v_machine_id
           AND pil.shelf_id   = v_shelf_id
           AND pil.boonz_product_id = v_boonz_product_id
           AND pil.status = 'Active'
           AND COALESCE(pil.current_stock,0) > 0
         ORDER BY pil.expiration_date ASC NULLS LAST
      LOOP
        EXIT WHEN v_remaining <= 0;
        v_take := LEAST(v_batch.current_stock, v_remaining);
        INSERT INTO refill_dispatching (
          machine_id, shelf_id, pod_product_id, boonz_product_id,
          dispatch_date, action, quantity, include, comment,
          from_warehouse_id, from_wh_inventory_id, expiry_date, pinned_at_plan_time,
          source_origin, from_machine_id,
          packed, picked_up, dispatched, returned, item_added
        ) VALUES (
          v_machine_id, v_shelf_id, v_pod_product_id, v_boonz_product_id,
          line.plan_date, v_action, v_take, true, v_dispatch_comment,
          v_primary_warehouse_id, NULL, v_batch.expiration_date, false,
          COALESCE(line.source_origin, 'warehouse'::public.source_origin_enum),
          CASE WHEN line.source_origin='internal_transfer' THEN line.from_machine_id ELSE NULL END,
          false, false, false, false, false
        ) RETURNING dispatch_id INTO v_new_dispatch_id;
        v_remaining := v_remaining - v_take;
        v_count := v_count + 1; v_remove_split := v_remove_split + 1;
      END LOOP;
      IF v_remaining > 0 THEN
        INSERT INTO refill_dispatching (
          machine_id, shelf_id, pod_product_id, boonz_product_id,
          dispatch_date, action, quantity, include, comment,
          from_warehouse_id, from_wh_inventory_id, expiry_date, pinned_at_plan_time,
          source_origin, from_machine_id,
          packed, picked_up, dispatched, returned, item_added
        ) VALUES (
          v_machine_id, v_shelf_id, v_pod_product_id, v_boonz_product_id,
          line.plan_date, v_action, v_remaining, true,
          COALESCE(NULLIF(v_dispatch_comment,'') || E'\n', '') || '[EXPIRY-TO-CONFIRM — remainder not attributable to a known batch (PRD-053)]',
          v_primary_warehouse_id, NULL, NULL, false,
          COALESCE(line.source_origin, 'warehouse'::public.source_origin_enum),
          CASE WHEN line.source_origin='internal_transfer' THEN line.from_machine_id ELSE NULL END,
          false, false, false, false, false
        ) RETURNING dispatch_id INTO v_new_dispatch_id;
        v_count := v_count + 1; v_remove_split := v_remove_split + 1;
      END IF;
      UPDATE refill_plan_output SET dispatched=true, dispatch_id=v_new_dispatch_id WHERE id=line.id;
      CONTINUE;
    END IF;

    v_pin_eligible := (v_action IN ('Refill','Add New'))
                      AND (COALESCE(line.source_origin::text, 'warehouse') = 'warehouse');
    v_pinned_wh_id := NULL;
    v_pinned_expiry := NULL;

    IF v_pin_eligible AND v_primary_warehouse_id IS NOT NULL THEN
      SELECT wh_inventory_id, expiration_date
        INTO v_pinned_wh_id, v_pinned_expiry
      FROM warehouse_inventory
       WHERE warehouse_id = v_primary_warehouse_id
         AND boonz_product_id = v_boonz_product_id
         AND status = 'Active'
         AND coalesce(warehouse_stock, 0) > 0
       ORDER BY expiration_date ASC NULLS LAST, wh_inventory_id ASC
       LIMIT 1;

      IF v_pinned_wh_id IS NULL THEN
        v_procurement_gaps := v_procurement_gaps + 1;
        INSERT INTO public.monitoring_alerts (source, severity, payload)
        VALUES (
          'procurement_gap', 'warning',
          jsonb_build_object(
            'title', format('Procurement gap: %s at %s', line.boonz_product_name, p_machine_name),
            'plan_date', p_plan_date, 'machine_name', p_machine_name, 'machine_id', v_machine_id,
            'boonz_product_id', v_boonz_product_id, 'boonz_product_name', line.boonz_product_name,
            'wh_id', v_primary_warehouse_id, 'action', v_action, 'qty_needed', line.quantity,
            'detected_by', 'push_plan_to_dispatch_FEFO_pin', 'detected_at', now()
          )
        );
      ELSE
        v_pinned_count := v_pinned_count + 1;
      END IF;
    END IF;

    INSERT INTO refill_dispatching (
      machine_id, shelf_id, pod_product_id, boonz_product_id,
      dispatch_date, action, quantity, include, comment,
      from_warehouse_id, from_wh_inventory_id, expiry_date, pinned_at_plan_time,
      source_origin, from_machine_id,
      packed, picked_up, dispatched, returned, item_added
    ) VALUES (
      v_machine_id, v_shelf_id, v_pod_product_id, v_boonz_product_id,
      line.plan_date, v_action, line.quantity, true, v_dispatch_comment,
      v_primary_warehouse_id, v_pinned_wh_id, v_pinned_expiry, v_pin_eligible,
      COALESCE(line.source_origin, 'warehouse'::public.source_origin_enum),
      CASE WHEN line.source_origin='internal_transfer' THEN line.from_machine_id ELSE NULL END,
      false, false, false, false, false
    ) RETURNING dispatch_id INTO v_new_dispatch_id;

    UPDATE refill_plan_output SET dispatched=true, dispatch_id=v_new_dispatch_id WHERE id=line.id;
    v_count := v_count + 1;
  END LOOP;

  -- PRD-071 WS-B: safety-net pairing pass (idempotent; failure logs, never fails the push)
  v_prev_via_trigger := current_setting('app.via_trigger', true);
  v_prev_mutation_reason := current_setting('app.mutation_reason', true);
  BEGIN
    v_pairing := public.pair_internal_transfer_m2m(p_plan_date, v_user_id);
  EXCEPTION WHEN OTHERS THEN
    v_pairing := jsonb_build_object('status','error','error', SQLERRM);
    INSERT INTO public.monitoring_alerts (source, severity, payload)
    VALUES ('m2m_pairing_failure', 'warning', jsonb_build_object(
      'title', format('M2M auto-pairing failed on push: %s @ %s', p_machine_name, p_plan_date),
      'plan_date', p_plan_date, 'machine_name', p_machine_name, 'machine_id', v_machine_id,
      'error', SQLERRM, 'detected_by', 'push_plan_to_dispatch_v7_prd071', 'detected_at', now()));
  END;
  PERFORM set_config('app.rpc_name', 'push_plan_to_dispatch', true);
  PERFORM set_config('app.via_trigger', COALESCE(v_prev_via_trigger, ''), true);
  PERFORM set_config('app.mutation_reason', COALESCE(v_prev_mutation_reason, ''), true);

  RETURN jsonb_build_object(
    'status','ok',
    'machine', p_machine_name,
    'lines_pushed', v_count,
    'lines_skipped_null_product', v_skipped,
    'lines_preserved_manual_edit', v_preserved,
    'lines_pinned_at_plan_time', v_pinned_count,
    'remove_split_lines', v_remove_split,
    'procurement_gaps_logged', v_procurement_gaps,
    'm2m_transfer_pairs', v_transfer_pairs,
    'm2m_transfer_deferred', v_transfer_deferred,
    'm2m_transfer_skipped', v_transfer_skipped,
    'm2m_pairing', v_pairing,
    'weimi_slot_guard', v_slot_guard,
    'rpc_version','v9_id_keyed_rpo'
  );
END $function$

CREATE OR REPLACE FUNCTION public.receive_dispatch_line(p_dispatch_id uuid, p_filled_quantity numeric, p_received_by uuid DEFAULT NULL::uuid, p_batch_breakdown jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_dispatch refill_dispatching%ROWTYPE;
  v_planned numeric; v_return_delta numeric; v_overfill numeric;
  v_consumer_row warehouse_inventory%ROWTYPE;
  v_wh_row warehouse_inventory%ROWTYPE;
  v_pod_id uuid; v_consumer_drawn numeric := 0; v_path text;
  v_default_wh uuid := '4bebef68-9e36-4a5c-9c2c-142f8dbdae85';
  v_target_wh uuid; v_pod_archived int := 0;
  v_breakdown_total numeric := 0;
  v_entry jsonb; v_entry_qty numeric; v_entry_expiry date; v_entry_wh_id uuid;
  v_existing_row warehouse_inventory%ROWTYPE;
  v_credit_summary jsonb := '[]'::jsonb;
  v_effective_expiry date;
  v_prior_active_merged int := 0;
  v_supply text;
BEGIN
  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'receive_dispatch_line', true);
  PERFORM set_config('app.provenance_reason', 'dispatch_receive', true);
  PERFORM set_config('app.source_event_id', p_dispatch_id::text, true);
  SELECT * INTO v_dispatch FROM refill_dispatching WHERE dispatch_id = p_dispatch_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Dispatch % not found', p_dispatch_id; END IF;
  IF v_dispatch.item_added = true THEN RAISE EXCEPTION 'Dispatch % already received', p_dispatch_id; END IF;
  IF p_filled_quantity < 0 THEN RAISE EXCEPTION 'filled_quantity cannot be negative'; END IF;
  v_planned := v_dispatch.quantity;
  v_return_delta := GREATEST(v_planned - p_filled_quantity, 0);
  v_overfill := GREATEST(p_filled_quantity - v_planned, 0);
  v_path := 'b2_fallback';
  v_target_wh := COALESCE(v_dispatch.from_warehouse_id, v_default_wh);
  IF v_dispatch.from_wh_inventory_id IS NOT NULL THEN
    SELECT expiration_date INTO v_effective_expiry FROM warehouse_inventory WHERE wh_inventory_id = v_dispatch.from_wh_inventory_id;
  ELSE
    v_effective_expiry := v_dispatch.expiry_date;
  END IF;
  PERFORM set_config('app.mutation_reason', format('B3 receive: dispatch %s — filled %s / planned %s by %s (breakdown=%s, effective_expiry=%s)', p_dispatch_id, p_filled_quantity, v_planned, COALESCE(p_received_by::text, 'system'), p_batch_breakdown IS NOT NULL, v_effective_expiry), true);
  IF v_dispatch.action IN ('Refill','Add New','Add') THEN
   -- PRD-056: M2M transfer dest leg. Stock arrives from the partner machine, not the warehouse:
   -- skip the consumer/WH draw, return, and overfill logic entirely; only write the dest pod_inventory
   -- below. Keeps the transfer WH-neutral on both legs.
   IF NOT COALESCE(v_dispatch.is_m2m, false) THEN
    IF v_dispatch.from_wh_inventory_id IS NOT NULL THEN
      SELECT * INTO v_consumer_row FROM warehouse_inventory WHERE wh_inventory_id = v_dispatch.from_wh_inventory_id FOR UPDATE;
      IF FOUND AND COALESCE(v_consumer_row.consumer_stock, 0) > 0 THEN v_path := 'b3_consumer_pinned'; ELSE v_consumer_row := NULL; END IF;
    END IF;
    IF v_consumer_row.wh_inventory_id IS NULL THEN
      SELECT * INTO v_consumer_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND COALESCE(consumer_stock, 0) > 0 AND (reserved_for_machine_id = v_dispatch.machine_id OR reserved_for_machine_id IS NULL) AND (expiration_date = v_effective_expiry OR v_effective_expiry IS NULL) ORDER BY (reserved_for_machine_id = v_dispatch.machine_id) DESC, consumer_stock DESC, reserved_at ASC LIMIT 1 FOR UPDATE;
      IF FOUND THEN v_path := 'b3_consumer_legacy'; END IF;
    END IF;
    IF v_consumer_row.wh_inventory_id IS NOT NULL THEN
      v_consumer_drawn := LEAST(p_filled_quantity, v_consumer_row.consumer_stock);
      UPDATE warehouse_inventory SET consumer_stock = GREATEST(COALESCE(consumer_stock, 0) - (v_consumer_drawn + v_return_delta), 0), warehouse_stock = COALESCE(warehouse_stock, 0) + v_return_delta, reserved_for_machine_id = CASE WHEN COALESCE(consumer_stock, 0) - (v_consumer_drawn + v_return_delta) <= 0 THEN NULL ELSE reserved_for_machine_id END, reserved_at = CASE WHEN COALESCE(consumer_stock, 0) - (v_consumer_drawn + v_return_delta) <= 0 THEN NULL ELSE reserved_at END WHERE wh_inventory_id = v_consumer_row.wh_inventory_id;
    ELSE
      IF v_return_delta > 0 THEN
        SELECT * INTO v_wh_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND status = 'Active' AND (expiration_date = v_effective_expiry OR v_effective_expiry IS NULL) ORDER BY (expiration_date = v_effective_expiry) DESC NULLS LAST, created_at DESC LIMIT 1 FOR UPDATE;
        IF FOUND THEN
          UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + v_return_delta WHERE wh_inventory_id = v_wh_row.wh_inventory_id;
        ELSE
          SELECT * INTO v_wh_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND (expiration_date = v_effective_expiry OR v_effective_expiry IS NULL) ORDER BY created_at DESC LIMIT 1 FOR UPDATE;
          IF FOUND THEN
            UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + v_return_delta WHERE wh_inventory_id = v_wh_row.wh_inventory_id;
          ELSE
            PERFORM set_config('app.provenance_reason','dispatch_return_unverified', true);
            INSERT INTO warehouse_inventory (boonz_product_id, warehouse_stock, expiration_date, status, batch_id, snapshot_date, warehouse_id) VALUES (v_dispatch.boonz_product_id, v_return_delta, v_effective_expiry, 'Active', format('RETURN-%s', v_dispatch.dispatch_date), CURRENT_DATE, v_target_wh);
            PERFORM set_config('app.provenance_reason','dispatch_receive', true);
          END IF;
        END IF;
      END IF;
    END IF;
    IF v_overfill > 0 THEN
      UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) - v_overfill WHERE wh_inventory_id = (SELECT wh_inventory_id FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND status = 'Active' AND COALESCE(warehouse_stock, 0) >= v_overfill AND (expiration_date = v_effective_expiry OR v_effective_expiry IS NULL) ORDER BY expiration_date ASC NULLS LAST LIMIT 1 FOR UPDATE);
    END IF;
   ELSE
     v_path := 'add_m2m_no_wh_draw';
   END IF;
    IF p_filled_quantity > 0 THEN
      WITH archived AS (UPDATE pod_inventory SET status = 'Inactive', removal_reason = format('merged_into_dispatch_%s_%s', v_dispatch.dispatch_date, p_dispatch_id::text), snapshot_at = now() WHERE machine_id = v_dispatch.machine_id AND shelf_id = v_dispatch.shelf_id AND boonz_product_id = v_dispatch.boonz_product_id AND status = 'Active' RETURNING current_stock, expiration_date), merge_stats AS (SELECT COALESCE(SUM(current_stock), 0)::numeric AS prior_qty, COUNT(*)::int AS prior_n, MIN(expiration_date) AS oldest_expiry FROM archived)
      INSERT INTO pod_inventory (machine_id, shelf_id, boonz_product_id, snapshot_date, current_stock, estimated_remaining, expiration_date, batch_id, status, snapshot_at, created_at) SELECT v_dispatch.machine_id, v_dispatch.shelf_id, v_dispatch.boonz_product_id, CURRENT_DATE, p_filled_quantity + ms.prior_qty, p_filled_quantity + ms.prior_qty, LEAST(v_effective_expiry, COALESCE(ms.oldest_expiry, v_effective_expiry)), CASE WHEN ms.prior_n > 0 THEN format('MERGED-DISPATCH-%s', v_dispatch.dispatch_date) ELSE format('DISPATCH-%s', v_dispatch.dispatch_date) END, 'Active', now(), now() FROM merge_stats ms RETURNING pod_inventory_id INTO v_pod_id;
      SELECT prior_n INTO v_prior_active_merged FROM (SELECT COUNT(*)::int AS prior_n FROM pod_inventory WHERE machine_id = v_dispatch.machine_id AND shelf_id = v_dispatch.shelf_id AND boonz_product_id = v_dispatch.boonz_product_id AND status = 'Inactive' AND removal_reason = format('merged_into_dispatch_%s_%s', v_dispatch.dispatch_date, p_dispatch_id::text)) AS s;
    END IF;
  ELSIF v_dispatch.action = 'Remove' THEN
    v_path := 'remove_single_expiry';
    SELECT source_of_supply INTO v_supply FROM public.product_mapping
     WHERE boonz_product_id = v_dispatch.boonz_product_id AND status = 'Active'
       AND (machine_id = v_dispatch.machine_id OR is_global_default)
     ORDER BY (machine_id = v_dispatch.machine_id) DESC, is_global_default ASC LIMIT 1;
    -- PRD-056: M2M transfer source leg. Unit moved to the partner machine, not the warehouse:
    -- skip ALL WH credit; only the source-pod archival below runs. Prevents transfer double-count.
    IF COALESCE(v_dispatch.is_m2m, false) THEN
      v_path := 'remove_m2m_no_wh_credit';
    ELSIF v_supply = 'venue_team' THEN
      v_path := 'remove_venue_team_no_wh_credit';
      INSERT INTO public.vox_return_log
        (dispatch_id, machine_id, boonz_product_id, qty, expiry_date, source_of_supply, received_by, reason)
      VALUES
        (p_dispatch_id, v_dispatch.machine_id, v_dispatch.boonz_product_id, p_filled_quantity,
         v_effective_expiry, v_supply, p_received_by,
         format('VOX venue_team REMOVE receipt; WH credit skipped (dispatch %s)', p_dispatch_id));
    ELSIF p_filled_quantity > 0 THEN
      IF p_batch_breakdown IS NOT NULL AND jsonb_typeof(p_batch_breakdown) = 'array' THEN
        v_path := 'remove_breakdown';
        SELECT COALESCE(SUM((e->>'qty')::numeric), 0) INTO v_breakdown_total FROM jsonb_array_elements(p_batch_breakdown) e;
        IF v_breakdown_total <> p_filled_quantity THEN RAISE EXCEPTION 'Breakdown total (%) must equal filled_quantity (%)', v_breakdown_total, p_filled_quantity; END IF;
        FOR v_entry IN SELECT * FROM jsonb_array_elements(p_batch_breakdown) LOOP
          v_entry_qty := (v_entry->>'qty')::numeric;
          IF v_entry_qty <= 0 THEN CONTINUE; END IF;
          v_entry_expiry := NULLIF(v_entry->>'expiry', '')::date;
          v_entry_wh_id := NULLIF(v_entry->>'wh_inventory_id', '')::uuid;
          IF v_entry_wh_id IS NOT NULL THEN
            SELECT * INTO v_existing_row FROM warehouse_inventory WHERE wh_inventory_id = v_entry_wh_id FOR UPDATE;
            IF NOT FOUND THEN RAISE EXCEPTION 'Breakdown row id % not found', v_entry_wh_id; END IF;
            UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + v_entry_qty, status = CASE WHEN status = 'Inactive' THEN 'Active' ELSE status END WHERE wh_inventory_id = v_existing_row.wh_inventory_id;
            v_credit_summary := v_credit_summary || jsonb_build_object('wh_inventory_id', v_existing_row.wh_inventory_id, 'expiry', v_existing_row.expiration_date, 'qty', v_entry_qty);
            CONTINUE;
          END IF;
          IF v_entry_expiry IS NULL THEN RAISE EXCEPTION 'Breakdown entry must include expiry or wh_inventory_id (got %)', v_entry; END IF;
          SELECT * INTO v_existing_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND warehouse_id = v_target_wh AND status = 'Active' AND expiration_date = v_entry_expiry ORDER BY created_at ASC LIMIT 1 FOR UPDATE;
          IF FOUND THEN
            UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + v_entry_qty WHERE wh_inventory_id = v_existing_row.wh_inventory_id;
            v_credit_summary := v_credit_summary || jsonb_build_object('wh_inventory_id', v_existing_row.wh_inventory_id, 'expiry', v_entry_expiry, 'qty', v_entry_qty, 'mode', 'existing');
          ELSE
            PERFORM set_config('app.provenance_reason','dispatch_return_unverified', true);
            INSERT INTO warehouse_inventory (boonz_product_id, warehouse_stock, expiration_date, status, batch_id, snapshot_date, warehouse_id) VALUES (v_dispatch.boonz_product_id, v_entry_qty, v_entry_expiry, 'Active', format('REMOVE-RECEIVE-%s', v_dispatch.dispatch_date), CURRENT_DATE, v_target_wh) RETURNING wh_inventory_id INTO v_entry_wh_id;
            PERFORM set_config('app.provenance_reason','dispatch_receive', true);
            v_credit_summary := v_credit_summary || jsonb_build_object('wh_inventory_id', v_entry_wh_id, 'expiry', v_entry_expiry, 'qty', v_entry_qty, 'mode', 'inserted');
          END IF;
        END LOOP;
      ELSIF v_effective_expiry IS NOT NULL THEN
        SELECT * INTO v_existing_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND warehouse_id = v_target_wh AND status = 'Active' AND expiration_date = v_effective_expiry ORDER BY created_at ASC LIMIT 1 FOR UPDATE;
        IF FOUND THEN
          UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + p_filled_quantity WHERE wh_inventory_id = v_existing_row.wh_inventory_id;
        ELSE
          PERFORM set_config('app.provenance_reason','dispatch_return_unverified', true);
          INSERT INTO warehouse_inventory (boonz_product_id, warehouse_stock, expiration_date, status, batch_id, snapshot_date, warehouse_id) VALUES (v_dispatch.boonz_product_id, p_filled_quantity, v_effective_expiry, 'Active', format('REMOVE-RECEIVE-%s', v_dispatch.dispatch_date), CURRENT_DATE, v_target_wh);
          PERFORM set_config('app.provenance_reason','dispatch_receive', true);
        END IF;
      ELSE
        v_path := 'remove_fefo_fallback';
        SELECT * INTO v_existing_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND warehouse_id = v_target_wh AND status = 'Active' AND expiration_date IS NOT NULL ORDER BY expiration_date ASC LIMIT 1 FOR UPDATE;
        IF FOUND THEN
          UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + p_filled_quantity WHERE wh_inventory_id = v_existing_row.wh_inventory_id;
        ELSE
          SELECT * INTO v_existing_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND warehouse_id = v_target_wh AND status = 'Active' ORDER BY created_at DESC LIMIT 1 FOR UPDATE;
          IF FOUND THEN
            UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + p_filled_quantity WHERE wh_inventory_id = v_existing_row.wh_inventory_id;
          ELSE
            RAISE EXCEPTION 'Cannot receive REMOVE dispatch %: effective_expiry is NULL and no Active warehouse_inventory row exists for boonz_product=%, warehouse=%. Pass p_batch_breakdown with explicit expiry.', p_dispatch_id, v_dispatch.boonz_product_id, v_target_wh;
          END IF;
        END IF;
      END IF;
    END IF;
    UPDATE pod_inventory SET status = 'Inactive', removal_reason = format('removed_via_dispatch_%s', p_dispatch_id) WHERE machine_id = v_dispatch.machine_id AND boonz_product_id = v_dispatch.boonz_product_id AND (shelf_id = v_dispatch.shelf_id OR v_dispatch.shelf_id IS NULL) AND status = 'Active';
    GET DIAGNOSTICS v_pod_archived = ROW_COUNT;
  END IF;
  UPDATE refill_dispatching SET filled_quantity = p_filled_quantity, item_added = true, dispatched = true, packed = true, picked_up = true WHERE dispatch_id = p_dispatch_id;
  RETURN jsonb_build_object('dispatch_id', p_dispatch_id, 'action', v_dispatch.action, 'filled_quantity', p_filled_quantity, 'planned_quantity', v_planned, 'return_delta', v_return_delta, 'overfill', v_overfill, 'pod_inventory_id', v_pod_id, 'pod_archived', v_pod_archived, 'prior_active_merged', v_prior_active_merged, 'consumer_drained', v_consumer_drawn, 'path', v_path, 'effective_expiry', v_effective_expiry, 'received_by', p_received_by, 'credit_summary', v_credit_summary, 'wh_credit_skipped', CASE WHEN COALESCE(v_dispatch.is_m2m,false) THEN 'm2m' WHEN v_supply = 'venue_team' THEN 'venue_team' ELSE NULL END, 'status', 'received');
END;
$function$

CREATE OR REPLACE FUNCTION public.record_actual_refill(p_machine_name text, p_plan_date date, p_lines jsonb, p_source text DEFAULT 'cs'::text, p_actor uuid DEFAULT NULL::uuid, p_reason text DEFAULT NULL::text, p_dry_run boolean DEFAULT true)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_machine_id uuid;
  v_event_id   uuid;
  v_line       jsonb;
  v_action     text;
  v_bpid       uuid;
  v_shelf_code text;
  v_shelf_id   uuid;
  v_qty        numeric;
  v_setmode    text;
  v_exp        date;
  v_wh         uuid;
  v_partner    text;
  v_partner_id uuid;
  v_notes      text;
  v_cur        numeric;
  v_newqty     numeric;
  v_whcur      numeric;
  v_whcs       numeric;
  v_whnew      numeric;
  v_pod_res    jsonb;
  v_pod_id     uuid;
  v_rpo_action text;
  v_applied    int := 0;
  v_lineno     int := 0;
BEGIN
  PERFORM set_config('app.via_rpc','true',true);
  PERFORM set_config('app.rpc_name','record_actual_refill',true);

  -- resolve + validate machine
  SELECT machine_id INTO v_machine_id FROM machines WHERE official_name = p_machine_name;
  IF v_machine_id IS NULL THEN RAISE EXCEPTION 'record_actual_refill: machine % not found', p_machine_name; END IF;
  IF p_lines IS NULL OR jsonb_array_length(p_lines) = 0 THEN RAISE EXCEPTION 'p_lines empty'; END IF;

  -- role: if a caller identity is present, it must be a manager role (skips when auth.uid() is NULL, e.g. MCP)
  IF p_actor IS NOT NULL THEN
    IF NOT EXISTS (SELECT 1 FROM user_profiles WHERE id = p_actor
                   AND role = ANY (ARRAY['warehouse','operator_admin','superadmin','manager'])) THEN
      RAISE EXCEPTION 'record_actual_refill: actor % is not an inventory manager', p_actor;
    END IF;
    -- impersonate so nested gated RPCs (adjust_warehouse_stock) authorize
    PERFORM set_config('request.jwt.claims',
      json_build_object('sub', p_actor::text, 'role','authenticated')::text, true);
  END IF;

  -- header (persists even if apply fails, so a failure is recorded)
  INSERT INTO refill_events (machine_id, plan_date, source, captured_by, status, reason)
  VALUES (v_machine_id, p_plan_date, p_source, p_actor,
          CASE WHEN p_dry_run THEN 'dry_run' ELSE 'pending' END, p_reason)
  RETURNING event_id INTO v_event_id;

  BEGIN
    FOR v_line IN SELECT * FROM jsonb_array_elements(p_lines) LOOP
      v_lineno   := v_lineno + 1;
      v_action   := v_line->>'action';
      v_bpid     := (v_line->>'boonz_product_id')::uuid;
      v_shelf_code := v_line->>'shelf_code';
      v_qty      := (v_line->>'qty')::numeric;
      v_setmode  := COALESCE(v_line->>'set_mode','delta');
      v_exp      := NULLIF(v_line->>'expiration_date','')::date;
      v_wh       := NULLIF(v_line->>'warehouse_id','')::uuid;
      v_partner  := v_line->>'partner_machine';
      v_notes    := v_line->>'notes';
      v_shelf_id := NULL; v_pod_id := NULL; v_partner_id := NULL;

      IF v_action IS NULL OR v_action NOT IN
         ('refill','remove','write_off','transfer_out','transfer_in','wh_return','wh_receive') THEN
        RAISE EXCEPTION 'line %: bad action %', v_lineno, v_action; END IF;
      IF v_bpid IS NULL THEN RAISE EXCEPTION 'line %: boonz_product_id required', v_lineno; END IF;
      IF NOT EXISTS (SELECT 1 FROM boonz_products WHERE product_id = v_bpid) THEN
        RAISE EXCEPTION 'line %: product % not found', v_lineno, v_bpid; END IF;
      IF v_partner IS NOT NULL THEN
        SELECT machine_id INTO v_partner_id FROM machines WHERE official_name = v_partner; END IF;

      -- resolve shelf for pod-affecting actions
      IF v_action IN ('refill','remove','write_off','transfer_out','transfer_in') THEN
        IF v_shelf_code IS NULL THEN RAISE EXCEPTION 'line %: shelf_code required for %', v_lineno, v_action; END IF;
        SELECT shelf_id INTO v_shelf_id FROM shelf_configurations
          WHERE machine_id = v_machine_id AND shelf_code = v_shelf_code;
        IF v_shelf_id IS NULL THEN RAISE EXCEPTION 'line %: shelf % not on machine', v_lineno, v_shelf_code; END IF;
      END IF;

      IF NOT p_dry_run THEN
        -- POD effect
        IF v_action IN ('refill','remove','write_off','transfer_out','transfer_in') THEN
          IF v_setmode = 'set' THEN
            v_newqty := v_qty;
          ELSE
            SELECT current_stock INTO v_cur FROM pod_inventory
              WHERE machine_id = v_machine_id AND shelf_id = v_shelf_id AND boonz_product_id = v_bpid
                AND status='Active' AND (expiration_date = v_exp OR (expiration_date IS NULL AND v_exp IS NULL))
              LIMIT 1;
            IF v_action IN ('remove','write_off','transfer_out') THEN
              v_newqty := GREATEST(COALESCE(v_cur,0) - v_qty, 0);
            ELSE
              v_newqty := COALESCE(v_cur,0) + v_qty;
            END IF;
          END IF;
          SELECT public.adjust_pod_inventory(
            p_machine_name, p_plan_date,
            jsonb_build_array(jsonb_build_object(
              'boonz_product_id', v_bpid, 'new_qty', v_newqty,
              'expiration_date', v_exp, 'shelf_code', v_shelf_code,
              'batch_id', 'RECORD-'||to_char(p_plan_date,'YYYY-MM-DD'))),
            COALESCE(p_reason,'record_actual_refill')) INTO v_pod_res;
          v_pod_id := (v_pod_res->'details'->0->>'pod_inventory_id')::uuid;
        END IF;

        -- WAREHOUSE effect
        IF v_wh IS NOT NULL THEN
          SELECT warehouse_stock, consumer_stock INTO v_whcur, v_whcs FROM warehouse_inventory
            WHERE boonz_product_id = v_bpid AND warehouse_id = v_wh AND status='Active'
              AND (expiration_date = v_exp OR (expiration_date IS NULL AND v_exp IS NULL))
            ORDER BY created_at DESC LIMIT 1;
          IF v_action IN ('wh_receive','wh_return') THEN
            v_whnew := COALESCE(v_whcur,0) + v_qty;
          ELSIF v_action = 'refill' THEN
            v_whnew := GREATEST(COALESCE(v_whcur,0) - v_qty, 0);
          ELSE
            v_whnew := NULL;
          END IF;
          IF v_whnew IS NOT NULL THEN
            PERFORM public.adjust_warehouse_stock(
              v_wh,
              jsonb_build_array(jsonb_build_object(
                'boonz_product_id', v_bpid, 'new_warehouse_stock', v_whnew,
                'new_consumer_stock', COALESCE(v_whcs,0), 'expiration_date', v_exp)),
              p_plan_date, COALESCE(p_reason,'record_actual_refill'));
          END IF;
        END IF;

        -- LOG effect (refill_plan_output) for machine-facing actions only
        v_rpo_action := CASE
          WHEN v_action IN ('refill','transfer_in') THEN 'Refill'
          WHEN v_action IN ('remove','write_off','transfer_out') THEN 'Remove'
          ELSE NULL END;
        IF v_rpo_action IS NOT NULL THEN
          INSERT INTO refill_plan_output
            (plan_date, machine_name, shelf_code, pod_product_name, boonz_product_name,
             action, quantity, operator_status, operator_comment, reviewed_at, dispatched, comment)
          SELECT p_plan_date, p_machine_name, v_shelf_code,
                 bp.boonz_product_name, bp.boonz_product_name, v_rpo_action, v_qty,
                 'approved',
                 COALESCE(p_reason,'record_actual_refill')
                   || CASE WHEN v_partner IS NOT NULL THEN ' ('||v_action||' '||v_partner||')' ELSE '' END,
                 now(), false, 'record_actual_refill'
          FROM boonz_products bp WHERE bp.product_id = v_bpid;
        END IF;
      END IF;

      INSERT INTO refill_event_lines
        (event_id, action, boonz_product_id, shelf_id, qty, set_mode, expiration_date,
         warehouse_id, partner_machine_id, result_pod_inventory_id, applied, notes)
      VALUES
        (v_event_id, v_action, v_bpid, v_shelf_id, v_qty, v_setmode, v_exp,
         v_wh, v_partner_id, v_pod_id, (NOT p_dry_run), v_notes);
      v_applied := v_applied + 1;
    END LOOP;

    IF p_dry_run THEN
      UPDATE refill_events SET status = 'dry_run' WHERE event_id = v_event_id;
    ELSE
      UPDATE refill_events SET status = 'applied', applied_at = now() WHERE event_id = v_event_id;
    END IF;
  EXCEPTION WHEN OTHERS THEN
    -- subtransaction rolled back ALL target writes + line inserts; record the failure on the header
    UPDATE refill_events SET status = 'failed', error_text = SQLERRM WHERE event_id = v_event_id;
    RETURN jsonb_build_object('status','failed','event_id',v_event_id,'failed_at_line',v_lineno,'error',SQLERRM);
  END;

  RETURN jsonb_build_object(
    'status', CASE WHEN p_dry_run THEN 'dry_run_ok' ELSE 'applied' END,
    'event_id', v_event_id, 'machine', p_machine_name, 'plan_date', p_plan_date,
    'lines', v_applied);
END;
$function$

CREATE OR REPLACE FUNCTION public.release_wh_quarantine(p_wh_inventory_id uuid, p_reason text, p_verified_by uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_row public.warehouse_inventory%ROWTYPE;
BEGIN
  IF auth.uid() IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.user_profiles
    WHERE id = auth.uid() AND role = ANY(ARRAY['warehouse','operator_admin','superadmin'])
  ) THEN
    RAISE EXCEPTION 'forbidden: release_wh_quarantine requires warehouse, operator_admin, or superadmin';
  END IF;

  IF p_wh_inventory_id IS NULL THEN
    RAISE EXCEPTION 'release_wh_quarantine: p_wh_inventory_id is required';
  END IF;
  IF COALESCE(p_reason, '') = '' OR length(p_reason) < 10 THEN
    RAISE EXCEPTION 'release_wh_quarantine: p_reason is required (>= 10 chars; what was verified)';
  END IF;

  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'release_wh_quarantine', true);
  PERFORM set_config('app.mutation_reason',
    format('release_wh_quarantine by %s: %s',
      COALESCE(p_verified_by::text, COALESCE(auth.uid()::text, 'system')), p_reason),
    true);

  SELECT * INTO v_row FROM public.warehouse_inventory
  WHERE wh_inventory_id = p_wh_inventory_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'release_wh_quarantine: wh_inventory_id % not found', p_wh_inventory_id;
  END IF;

  IF NOT v_row.quarantined THEN
    RETURN jsonb_build_object(
      'status', 'noop', 'wh_inventory_id', p_wh_inventory_id,
      'message', 'row is not quarantined',
      'provenance_reason', v_row.provenance_reason);
  END IF;

  UPDATE public.warehouse_inventory
     SET provenance_reason = 'manual_adjust'
   WHERE wh_inventory_id = p_wh_inventory_id;

  RETURN jsonb_build_object(
    'status', 'released',
    'wh_inventory_id', p_wh_inventory_id,
    'boonz_product_id', v_row.boonz_product_id,
    'old_provenance_reason', v_row.provenance_reason,
    'new_provenance_reason', 'manual_adjust',
    'now_quarantined', false,
    'wh_status', v_row.status,
    'expiration_date', v_row.expiration_date,
    'verified_by', p_verified_by,
    'reason', p_reason,
    'note', 'pickable only if Active, in-date, stock>0 (governed by v_wh_pickable)');
END $function$

CREATE OR REPLACE FUNCTION public.repack_machine(p_machine_name text, p_dispatch_date date DEFAULT NULL::date, p_reason text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller_role      text;
  v_machine_id       uuid;
  v_today            date := (CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Dubai')::date;
  v_target_date      date;
  v_returned_count   int := 0;
  v_failed_returns   int := 0;
  v_resets_done      int := 0;
  v_pushed           int := 0;
  v_dispatched_count int := 0;
  v_row              record;
  v_push_result      jsonb;
BEGIN
  PERFORM set_config('app.via_rpc','true',true);
  PERFORM set_config('app.rpc_name','repack_machine',true);
  PERFORM set_config('app.mutation_reason',
    format('repack_machine: %s for %s (reason: %s)',
           p_machine_name,
           COALESCE(p_dispatch_date, (CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Dubai')::date),
           COALESCE(p_reason,'none')),
    true);

  -- Caller role guard
  SELECT role INTO v_caller_role FROM user_profiles WHERE id = auth.uid();
  IF v_caller_role NOT IN ('warehouse','operator_admin','superadmin','manager') THEN
    RETURN jsonb_build_object('status','error','error','Insufficient role');
  END IF;

  v_target_date := COALESCE(p_dispatch_date, v_today);

  SELECT machine_id INTO v_machine_id FROM machines WHERE official_name = p_machine_name;
  IF v_machine_id IS NULL THEN
    RETURN jsonb_build_object('status','error','error','Machine not found: ' || p_machine_name);
  END IF;

  -- 🛑 Dispatch gate: refuse repack if ANY row for this (machine, date) is dispatched=true.
  -- Once the bag has been dispatched, returning stock to the warehouse is no longer accurate.
  SELECT COUNT(*) INTO v_dispatched_count
  FROM refill_dispatching
  WHERE machine_id    = v_machine_id
    AND dispatch_date = v_target_date
    AND dispatched    = true;

  IF v_dispatched_count > 0 THEN
    RETURN jsonb_build_object(
      'status','error',
      'error','cannot_repack_after_dispatch',
      'message', format('Cannot repack %s for %s — %s row(s) already dispatched.',
                        p_machine_name, v_target_date, v_dispatched_count),
      'dispatched_count', v_dispatched_count,
      'machine', p_machine_name,
      'dispatch_date', v_target_date
    );
  END IF;

  -- Step 1: Return stock & mark each packed-not-picked-up row terminal
  FOR v_row IN
    SELECT dispatch_id, shelf_id, boonz_product_id, action
    FROM refill_dispatching
    WHERE machine_id    = v_machine_id
      AND dispatch_date = v_target_date
      AND packed        = true
      AND picked_up     = false
      AND returned      = false
      AND item_added    = false
    ORDER BY created_at
  LOOP
    BEGIN
      PERFORM public.return_dispatch_line(v_row.dispatch_id, 'superseded_by_repack');
      v_returned_count := v_returned_count + 1;
    EXCEPTION WHEN OTHERS THEN
      v_failed_returns := v_failed_returns + 1;
      RAISE WARNING 'repack_machine: return_dispatch_line failed for %, error: %',
        v_row.dispatch_id, SQLERRM;
    END;
  END LOOP;

  -- Step 2: Reset matching plan rows so push_plan_to_dispatch can re-mirror.
  -- Only reset rows whose 1:1 matching dispatch row is now terminal AND not received.
  UPDATE refill_plan_output rpo
  SET dispatched = false
  WHERE rpo.plan_date        = v_target_date
    AND rpo.machine_name     = p_machine_name
    AND rpo.operator_status  = 'approved'
    AND rpo.dispatched       = true
    AND NOT EXISTS (
      -- skip plan rows whose dispatch was successfully received (item_added=true)
      SELECT 1
      FROM refill_dispatching rd
      JOIN machines m ON m.machine_id = rd.machine_id
      LEFT JOIN shelf_configurations sc ON sc.shelf_id = rd.shelf_id
      WHERE m.official_name = rpo.machine_name
        AND rd.dispatch_date = rpo.plan_date
        AND COALESCE(sc.shelf_code,'') = COALESCE(rpo.shelf_code,'')
        AND rd.item_added = true
    );
  GET DIAGNOSTICS v_resets_done = ROW_COUNT;

  -- Step 3: Push the plan rows fresh
  IF v_resets_done > 0 THEN
    v_push_result := public.push_plan_to_dispatch(p_machine_name, v_target_date);
    v_pushed := COALESCE((v_push_result->>'lines_pushed')::int, 0);
  END IF;

  RETURN jsonb_build_object(
    'status',           'ok',
    'machine',          p_machine_name,
    'dispatch_date',    v_target_date,
    'returned_count',   v_returned_count,
    'failed_returns',   v_failed_returns,
    'plan_rows_reset',  v_resets_done,
    'fresh_dispatch_rows_created', v_pushed,
    'reason',           p_reason
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.reset_and_restitch(p_plan_date date, p_machine_ids uuid[], p_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user_id        uuid;
  v_machine_names  text[];
  v_dispatched     integer;
  v_reset          integer;
  v_approved_total integer;
  v_finalize       jsonb;
  v_approve        jsonb;
  v_stitch         jsonb;
BEGIN
  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'reset_and_restitch', true);

  v_user_id := auth.uid();
  IF v_user_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.user_profiles up
    WHERE up.id = v_user_id AND up.role = ANY(ARRAY['operator_admin','superadmin'])
  ) THEN
    RAISE EXCEPTION 'reset_and_restitch: caller % lacks operator_admin/superadmin role', v_user_id;
  END IF;

  IF p_plan_date IS NULL THEN RAISE EXCEPTION 'p_plan_date required'; END IF;
  IF p_machine_ids IS NULL OR array_length(p_machine_ids, 1) IS NULL THEN
    RAISE EXCEPTION 'p_machine_ids required (non-empty array)';
  END IF;
  IF p_reason IS NULL OR length(trim(p_reason)) < 10 THEN
    RAISE EXCEPTION 'p_reason required (>= 10 chars)';
  END IF;

  SELECT array_agg(m.official_name) INTO v_machine_names
    FROM public.machines m WHERE m.machine_id = ANY(p_machine_ids);
  IF v_machine_names IS NULL OR array_length(v_machine_names, 1) <> array_length(p_machine_ids, 1) THEN
    RAISE EXCEPTION 'reset_and_restitch: one or more machine_ids not found';
  END IF;

  SELECT COUNT(*) INTO v_dispatched
    FROM public.refill_plan_output rpo
   WHERE rpo.plan_date = p_plan_date
     AND rpo.machine_name = ANY(v_machine_names)
     AND rpo.operator_status <> 'pending';
  IF v_dispatched > 0 THEN
    RAISE EXCEPTION 'reset_and_restitch: % subset dispatch line(s) past pending; refusing to reset dispatched machine(s)', v_dispatched;
  END IF;

  UPDATE public.pod_refill_plan
     SET status     = 'superseded',
         reasoning  = COALESCE(reasoning, '{}'::jsonb)
                      || jsonb_build_object('reset_and_restitch', p_reason, 'reset_at', now()),
         updated_at = now()
   WHERE plan_date  = p_plan_date
     AND machine_id = ANY(p_machine_ids)
     AND status NOT IN ('superseded','voided');
  GET DIAGNOSTICS v_reset = ROW_COUNT;

  v_finalize := public.engine_finalize_pod(p_plan_date, p_machine_ids);
  v_approve  := public.approve_pod_refill_plan(p_plan_date, v_machine_names);

  SELECT COUNT(*) INTO v_approved_total
    FROM public.pod_refill_plan
   WHERE plan_date = p_plan_date AND status = 'approved';
  IF v_approved_total > 0 THEN
    v_stitch := public.stitch_pod_to_boonz(p_plan_date, false);
  ELSE
    v_stitch := jsonb_build_object('status','skipped','reason','no approved rows after re-derive');
  END IF;

  RETURN jsonb_build_object(
    'reset_and_restitch', 'done',
    'plan_date',     p_plan_date,
    'machine_ids',   p_machine_ids,
    'machine_names', v_machine_names,
    'rows_reset',    v_reset,
    'finalize',      v_finalize,
    'approve',       v_approve,
    'stitch',        v_stitch,
    'engine_version','v1_compose_finalize_approve_stitch'
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.reset_approved_undispatched(p_plan_date date, p_machine_ids uuid[], p_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid           uuid := (SELECT auth.uid());
  v_role          text;
  v_machine_names text[];
  v_blocked       integer;
  v_disp          record;
  v_skipped       integer := 0;
  v_rpo_reset     integer := 0;
BEGIN
  -- Article 4: role gate (service/NULL context bypasses, mirrors reset_and_restitch)
  IF v_uid IS NOT NULL THEN
    SELECT role INTO v_role FROM public.user_profiles WHERE id = v_uid;
    IF v_role IS NULL OR v_role NOT IN ('operator_admin','superadmin') THEN
      RAISE EXCEPTION 'reset_approved_undispatched: forbidden for role %', COALESCE(v_role,'unknown');
    END IF;
  END IF;

  -- Article 4: input validation
  IF p_plan_date IS NULL THEN RAISE EXCEPTION 'p_plan_date required'; END IF;
  IF p_machine_ids IS NULL OR array_length(p_machine_ids,1) IS NULL THEN
    RAISE EXCEPTION 'p_machine_ids required (non-empty array)';
  END IF;
  IF p_reason IS NULL OR length(trim(p_reason)) < 10 THEN
    RAISE EXCEPTION 'p_reason required (>= 10 chars)';
  END IF;

  SELECT array_agg(m.official_name) INTO v_machine_names
    FROM public.machines m WHERE m.machine_id = ANY(p_machine_ids);
  IF v_machine_names IS NULL OR array_length(v_machine_names,1) <> array_length(p_machine_ids,1) THEN
    RAISE EXCEPTION 'reset_approved_undispatched: one or more machine_ids not found';
  END IF;

  -- Article 5 guard: refuse if any in-scope approved row is unsafe to reverse
  SELECT COUNT(*) INTO v_blocked
    FROM public.refill_plan_output rpo
    JOIN public.refill_dispatching rd ON rd.dispatch_id = rpo.dispatch_id
   WHERE rpo.plan_date = p_plan_date
     AND rpo.machine_name = ANY(v_machine_names)
     AND rpo.operator_status = 'approved'
     AND (COALESCE(rd.dispatched,false) = true
          OR COALESCE(rd.picked_up,false) = true
          OR COALESCE(rd.packed,false) = true
          OR rd.from_wh_inventory_id IS NOT NULL
          OR COALESCE(rd.cancelled,false) = true);
  IF v_blocked > 0 THEN
    RAISE EXCEPTION 'reset_approved_undispatched: % approved row(s) dispatched/picked_up/packed/WH-bound/cancelled; refusing', v_blocked;
  END IF;

  -- Neutralize the open dispatch rows via the allowlisted canonical RPC (skipped + include=false)
  FOR v_disp IN
    SELECT rd.dispatch_id
      FROM public.refill_plan_output rpo
      JOIN public.refill_dispatching rd ON rd.dispatch_id = rpo.dispatch_id
     WHERE rpo.plan_date = p_plan_date
       AND rpo.machine_name = ANY(v_machine_names)
       AND rpo.operator_status = 'approved'
       AND COALESCE(rd.skipped,false) = false
       AND COALESCE(rd.cancelled,false) = false
  LOOP
    PERFORM public.skip_dispatch_line(v_disp.dispatch_id, p_reason);
    v_skipped := v_skipped + 1;
  END LOOP;

  -- Article 4/8: re-stamp GUCs for the rpo audit (skip_dispatch_line overwrote app.rpc_name)
  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'reset_approved_undispatched', true);
  PERFORM set_config('app.mutation_reason', p_reason, true);

  -- Article 5: guarded backward transition approved -> pending
  UPDATE public.refill_plan_output
     SET operator_status = 'pending',
         dispatch_id     = NULL,
         dispatched      = false
   WHERE plan_date = p_plan_date
     AND machine_name = ANY(v_machine_names)
     AND operator_status = 'approved';
  GET DIAGNOSTICS v_rpo_reset = ROW_COUNT;

  RETURN jsonb_build_object(
    'status','ok',
    'plan_date', p_plan_date,
    'machine_names', v_machine_names,
    'dispatch_rows_skipped', v_skipped,
    'rpo_reset_to_pending', v_rpo_reset,
    'reason', p_reason
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.return_dispatch_line(p_dispatch_id uuid, p_return_reason text DEFAULT NULL::text, p_returned_by uuid DEFAULT NULL::uuid, p_batch_breakdown jsonb DEFAULT NULL::jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE
  v_dispatch refill_dispatching%ROWTYPE;
  v_consumer_row warehouse_inventory%ROWTYPE;
  v_return_qty numeric;
  v_default_wh uuid := '4bebef68-9e36-4a5c-9c2c-142f8dbdae85';
  v_target_wh uuid;
  v_pod_archived int := 0;
  v_path text := 'unknown';
  v_breakdown_total numeric := 0;
  v_entry jsonb;
  v_entry_qty numeric;
  v_entry_expiry date;
  v_entry_wh_id uuid;
  v_existing_row warehouse_inventory%ROWTYPE;
  v_credit_summary jsonb := '[]'::jsonb;
  v_effective_expiry date;
BEGIN
  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'return_dispatch_line', true);
  PERFORM set_config('app.provenance_reason', 'dispatch_return', true);
  PERFORM set_config('app.source_event_id', p_dispatch_id::text, true);
  SELECT * INTO v_dispatch FROM refill_dispatching WHERE dispatch_id = p_dispatch_id FOR UPDATE;
  IF NOT FOUND THEN RAISE EXCEPTION 'Dispatch % not found', p_dispatch_id; END IF;
  IF v_dispatch.returned = true THEN RETURN jsonb_build_object('dispatch_id', p_dispatch_id, 'status', 'already_returned', 'message', 'This dispatch was already returned, no changes made'); END IF;
  IF v_dispatch.item_added = true THEN RAISE EXCEPTION 'Dispatch % already received (item_added=true), cannot return', p_dispatch_id; END IF;
  -- PRD-028 dispatch-state guards (Incident B, 2026-06-12): a line that is skipped,
  -- cancelled, or excluded AND was never packed nor picked up has nothing physical to
  -- return. Flagged lines that WERE packed stay returnable: that is the recovery path
  -- (Incident A) and the EOD sweep contract (packed=true, picked_up=false).
  IF (v_dispatch.skipped = true OR v_dispatch.cancelled = true OR COALESCE(v_dispatch.include, true) = false)
     AND v_dispatch.packed = false AND v_dispatch.picked_up = false THEN
    RAISE EXCEPTION 'return_dispatch_line: dispatch % is % (skip_reason: %) and was never packed or picked up. Nothing physical to return.',
      p_dispatch_id,
      CASE WHEN v_dispatch.skipped THEN 'SKIPPED' WHEN v_dispatch.cancelled THEN 'CANCELLED' ELSE 'EXCLUDED (include=false)' END,
      COALESCE(v_dispatch.skip_reason, 'no reason recorded');
  END IF;
  -- System-actor guard: no human actor AND nothing physical = refuse. This is the
  -- Dispatch Complete auto-return burst (return_dispatch_line by: system x5).
  -- eod_auto_release_unpicked only targets packed=true lines, so it never hits this.
  IF p_returned_by IS NULL AND v_dispatch.packed = false AND v_dispatch.picked_up = false THEN
    RAISE EXCEPTION 'return_dispatch_line: dispatch % has no actor (system call) and was never packed or picked up. Refusing system return of a non-physical line.', p_dispatch_id;
  END IF;

  v_target_wh := COALESCE(v_dispatch.from_warehouse_id, v_default_wh);
  IF v_dispatch.from_wh_inventory_id IS NOT NULL THEN
    SELECT expiration_date INTO v_effective_expiry FROM warehouse_inventory WHERE wh_inventory_id = v_dispatch.from_wh_inventory_id;
  ELSE
    v_effective_expiry := v_dispatch.expiry_date;
  END IF;
  IF v_dispatch.action = 'Remove' THEN
    v_return_qty := ABS(v_dispatch.quantity);
    v_path := 'remove';
    PERFORM set_config('app.mutation_reason', format('return_dispatch_line REMOVE: dispatch %s, %s units (reason: %s, by: %s, breakdown=%s, effective_expiry=%s)', p_dispatch_id, v_return_qty, COALESCE(p_return_reason, 'confirmed_removal'), COALESCE(p_returned_by::text, 'system'), p_batch_breakdown IS NOT NULL, v_effective_expiry), true);
    IF v_return_qty > 0 THEN
      IF p_batch_breakdown IS NOT NULL AND jsonb_typeof(p_batch_breakdown) = 'array' THEN
        v_path := 'remove_breakdown';
        SELECT COALESCE(SUM((e->>'qty')::numeric), 0) INTO v_breakdown_total FROM jsonb_array_elements(p_batch_breakdown) e;
        IF v_breakdown_total <> v_return_qty THEN RAISE EXCEPTION 'Breakdown total (%) must equal dispatch quantity (%)', v_breakdown_total, v_return_qty; END IF;
        FOR v_entry IN SELECT * FROM jsonb_array_elements(p_batch_breakdown) LOOP
          v_entry_qty := (v_entry->>'qty')::numeric;
          IF v_entry_qty <= 0 THEN CONTINUE; END IF;
          v_entry_expiry := NULLIF(v_entry->>'expiry', '')::date;
          v_entry_wh_id := NULLIF(v_entry->>'wh_inventory_id', '')::uuid;
          IF v_entry_wh_id IS NOT NULL THEN
            SELECT * INTO v_existing_row FROM warehouse_inventory WHERE wh_inventory_id = v_entry_wh_id FOR UPDATE;
            IF NOT FOUND THEN RAISE EXCEPTION 'Breakdown row id % not found', v_entry_wh_id; END IF;
            UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + v_entry_qty, status = CASE WHEN status = 'Inactive' THEN 'Active' ELSE status END WHERE wh_inventory_id = v_existing_row.wh_inventory_id;
            v_credit_summary := v_credit_summary || jsonb_build_object('wh_inventory_id', v_existing_row.wh_inventory_id, 'expiry', v_existing_row.expiration_date, 'qty', v_entry_qty);
            CONTINUE;
          END IF;
          IF v_entry_expiry IS NULL THEN RAISE EXCEPTION 'Breakdown entry must include either expiry or wh_inventory_id (got %)', v_entry; END IF;
          SELECT * INTO v_existing_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND warehouse_id = v_target_wh AND status = 'Active' AND expiration_date = v_entry_expiry ORDER BY created_at ASC LIMIT 1 FOR UPDATE;
          IF FOUND THEN
            UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + v_entry_qty WHERE wh_inventory_id = v_existing_row.wh_inventory_id;
            v_credit_summary := v_credit_summary || jsonb_build_object('wh_inventory_id', v_existing_row.wh_inventory_id, 'expiry', v_entry_expiry, 'qty', v_entry_qty, 'mode', 'existing');
          ELSE
            PERFORM set_config('app.provenance_reason','dispatch_return_unverified', true);
            INSERT INTO warehouse_inventory (boonz_product_id, warehouse_stock, expiration_date, status, batch_id, snapshot_date, warehouse_id) VALUES (v_dispatch.boonz_product_id, v_entry_qty, v_entry_expiry, 'Active', format('REMOVE-RETURN-%s', v_dispatch.dispatch_date), CURRENT_DATE, v_target_wh) RETURNING wh_inventory_id INTO v_entry_wh_id;
            PERFORM set_config('app.provenance_reason','dispatch_return', true);
            v_credit_summary := v_credit_summary || jsonb_build_object('wh_inventory_id', v_entry_wh_id, 'expiry', v_entry_expiry, 'qty', v_entry_qty, 'mode', 'inserted');
          END IF;
        END LOOP;
      ELSIF v_effective_expiry IS NOT NULL THEN
        v_path := 'remove_single_expiry';
        SELECT * INTO v_existing_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND warehouse_id = v_target_wh AND status = 'Active' AND expiration_date = v_effective_expiry ORDER BY created_at ASC LIMIT 1 FOR UPDATE;
        IF FOUND THEN
          UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + v_return_qty WHERE wh_inventory_id = v_existing_row.wh_inventory_id;
        ELSE
          PERFORM set_config('app.provenance_reason','dispatch_return_unverified', true);
          INSERT INTO warehouse_inventory (boonz_product_id, warehouse_stock, expiration_date, status, batch_id, snapshot_date, warehouse_id) VALUES (v_dispatch.boonz_product_id, v_return_qty, v_effective_expiry, 'Active', format('REMOVE-RETURN-%s', v_dispatch.dispatch_date), CURRENT_DATE, v_target_wh);
          PERFORM set_config('app.provenance_reason','dispatch_return', true);
        END IF;
      ELSE
        v_path := 'remove_fefo_fallback';
        SELECT * INTO v_existing_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND warehouse_id = v_target_wh AND status = 'Active' AND expiration_date IS NOT NULL ORDER BY expiration_date ASC LIMIT 1 FOR UPDATE;
        IF FOUND THEN
          UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + v_return_qty WHERE wh_inventory_id = v_existing_row.wh_inventory_id;
        ELSE
          SELECT * INTO v_existing_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND warehouse_id = v_target_wh AND status = 'Active' ORDER BY created_at DESC LIMIT 1 FOR UPDATE;
          IF FOUND THEN
            UPDATE warehouse_inventory SET warehouse_stock = COALESCE(warehouse_stock, 0) + v_return_qty WHERE wh_inventory_id = v_existing_row.wh_inventory_id;
          ELSE
            RAISE EXCEPTION 'Cannot return REMOVE dispatch %: effective_expiry is NULL and no Active warehouse_inventory row exists for boonz_product=%, warehouse=%. Pass p_batch_breakdown with explicit expiry.', p_dispatch_id, v_dispatch.boonz_product_id, v_target_wh;
          END IF;
        END IF;
      END IF;
    END IF;
    UPDATE pod_inventory SET status = 'Inactive', removal_reason = format('removed_via_dispatch_%s', p_dispatch_id) WHERE machine_id = v_dispatch.machine_id AND boonz_product_id = v_dispatch.boonz_product_id AND (shelf_id = v_dispatch.shelf_id OR v_dispatch.shelf_id IS NULL) AND status = 'Active';
    GET DIAGNOSTICS v_pod_archived = ROW_COUNT;
  ELSE
    v_return_qty := COALESCE(v_dispatch.filled_quantity, v_dispatch.quantity);
    PERFORM set_config('app.mutation_reason', format('return_dispatch_line: dispatch %s, %s units (reason: %s, by: %s, effective_expiry=%s)', p_dispatch_id, v_return_qty, COALESCE(p_return_reason, 'none'), COALESCE(p_returned_by::text, 'system'), v_effective_expiry), true);
    IF v_return_qty > 0 THEN
      IF v_dispatch.from_wh_inventory_id IS NOT NULL THEN
        SELECT * INTO v_consumer_row FROM warehouse_inventory WHERE wh_inventory_id = v_dispatch.from_wh_inventory_id FOR UPDATE;
        IF FOUND AND COALESCE(v_consumer_row.consumer_stock, 0) > 0 THEN v_path := 'pinned'; ELSE v_consumer_row := NULL; END IF;
      END IF;
      IF v_consumer_row.wh_inventory_id IS NULL THEN
        SELECT * INTO v_consumer_row FROM warehouse_inventory WHERE boonz_product_id = v_dispatch.boonz_product_id AND COALESCE(consumer_stock, 0) > 0 AND (reserved_for_machine_id = v_dispatch.machine_id OR reserved_for_machine_id IS NULL) AND (expiration_date = v_effective_expiry OR v_effective_expiry IS NULL) ORDER BY (reserved_for_machine_id = v_dispatch.machine_id) DESC, consumer_stock DESC LIMIT 1 FOR UPDATE;
        IF FOUND THEN v_path := 'legacy'; END IF;
      END IF;
      IF v_consumer_row.wh_inventory_id IS NOT NULL THEN
        UPDATE warehouse_inventory SET consumer_stock  = GREATEST(COALESCE(consumer_stock, 0) - v_return_qty, 0), warehouse_stock = COALESCE(warehouse_stock, 0) + v_return_qty, reserved_for_machine_id = CASE WHEN COALESCE(consumer_stock, 0) - v_return_qty <= 0 THEN NULL ELSE reserved_for_machine_id END, reserved_at = CASE WHEN COALESCE(consumer_stock, 0) - v_return_qty <= 0 THEN NULL ELSE reserved_at END WHERE wh_inventory_id = v_consumer_row.wh_inventory_id;
      END IF;
    END IF;
  END IF;
  UPDATE refill_dispatching SET returned = true, dispatched = true, filled_quantity = 0, return_reason = p_return_reason WHERE dispatch_id = p_dispatch_id;
  RETURN jsonb_build_object('dispatch_id', p_dispatch_id, 'action', v_dispatch.action, 'return_qty', v_return_qty, 'return_reason', p_return_reason, 'returned_by', p_returned_by, 'consumer_drained', v_consumer_row.wh_inventory_id IS NOT NULL, 'pod_archived', v_pod_archived, 'path', v_path, 'effective_expiry', v_effective_expiry, 'credit_summary', v_credit_summary, 'status', 'returned');
END;
$function$

CREATE OR REPLACE FUNCTION public.set_machine_warehouse(p_machine_id uuid, p_primary_warehouse_id uuid, p_secondary_warehouse_id uuid DEFAULT NULL::uuid, p_reason text DEFAULT NULL::text)
 RETURNS machines
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role       text;
  v_venue      text;
  v_wh_central uuid := '4bebef68-9e36-4a5c-9c2c-142f8dbdae85';
  v_result     public.machines;
BEGIN
  -- Article 4: role validation (config action -> admin/manager only)
  SELECT role INTO v_role FROM public.user_profiles WHERE id = (SELECT auth.uid());
  IF v_role IS NULL OR v_role <> ALL (ARRAY['operator_admin','superadmin','manager']) THEN
    RAISE EXCEPTION 'set_machine_warehouse: caller role % not permitted', COALESCE(v_role, '<none>');
  END IF;

  -- Article 4: input validation
  IF p_machine_id IS NULL OR p_primary_warehouse_id IS NULL THEN
    RAISE EXCEPTION 'set_machine_warehouse: machine_id and primary_warehouse_id are required';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM public.warehouses WHERE warehouse_id = p_primary_warehouse_id) THEN
    RAISE EXCEPTION 'set_machine_warehouse: primary_warehouse_id % not found', p_primary_warehouse_id;
  END IF;
  IF p_secondary_warehouse_id IS NOT NULL
     AND NOT EXISTS (SELECT 1 FROM public.warehouses WHERE warehouse_id = p_secondary_warehouse_id) THEN
    RAISE EXCEPTION 'set_machine_warehouse: secondary_warehouse_id % not found', p_secondary_warehouse_id;
  END IF;
  IF p_secondary_warehouse_id IS NOT NULL AND p_secondary_warehouse_id = p_primary_warehouse_id THEN
    RAISE EXCEPTION 'set_machine_warehouse: primary and secondary warehouse must differ';
  END IF;

  SELECT venue_group INTO v_venue FROM public.machines WHERE machine_id = p_machine_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'set_machine_warehouse: machine % not found', p_machine_id;
  END IF;

  -- VOX invariant (belt-and-suspenders with the table CHECK)
  IF COALESCE(v_venue, '') <> 'VOX' AND p_primary_warehouse_id <> v_wh_central THEN
    RAISE EXCEPTION 'set_machine_warehouse: non-VOX machine % must have primary = WH_CENTRAL', p_machine_id;
  END IF;

  -- Article 8: audit attribution for the generic trigger
  PERFORM set_config('app.via_rpc', 'true', true);
  PERFORM set_config('app.rpc_name', 'set_machine_warehouse', true);

  UPDATE public.machines
     SET primary_warehouse_id   = p_primary_warehouse_id,
         secondary_warehouse_id = p_secondary_warehouse_id,
         updated_at             = now()
   WHERE machine_id = p_machine_id
  RETURNING * INTO v_result;

  RETURN v_result;
END;
$function$

CREATE OR REPLACE FUNCTION public.write_refill_plan(p_plan_date date, p_lines jsonb)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  line           jsonb;
  v_count        int := 0;
  v_machine_names text[];
  v_user_id      uuid;
  v_errors       jsonb := '[]'::jsonb;
  v_line_idx     int := 0;
  v_action       text;
  v_shelf        text;
  v_machine      text;
  v_product      text;
  v_qty          int;
  v_seen_keys    text[] := '{}';
  v_dup_key      text;
  v_valid_actions text[] := ARRAY['Refill','Add New','Remove','Machine To Warehouse'];
  v_stale_pending int := 0;
BEGIN
  PERFORM set_config('app.via_rpc',  'true', true);
  PERFORM set_config('app.rpc_name', 'write_refill_plan', true);

  v_user_id := auth.uid();
  IF v_user_id IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM public.user_profiles
    WHERE id = v_user_id AND role = ANY (ARRAY['operator_admin','superadmin','manager'])
  ) THEN
    RAISE EXCEPTION 'write_refill_plan: caller % lacks required role', v_user_id;
  END IF;

  IF p_plan_date IS NULL OR p_plan_date < CURRENT_DATE THEN
    RETURN jsonb_build_object('status','error','reason','p_plan_date must be today or future','plan_date',p_plan_date);
  END IF;

  IF p_lines IS NULL OR jsonb_array_length(p_lines) = 0 THEN
    RETURN jsonb_build_object('status','error','reason','p_lines is empty or null');
  END IF;

  FOR line IN SELECT * FROM jsonb_array_elements(p_lines)
  LOOP
    v_line_idx := v_line_idx + 1;
    v_action   := line->>'action';
    v_shelf    := line->>'shelf_code';
    v_machine  := line->>'machine_name';
    v_product  := line->>'boonz_product_name';
    v_qty      := (line->>'quantity')::int;

    IF v_action IS NULL OR NOT (v_action = ANY(v_valid_actions)) THEN
      v_errors := v_errors || jsonb_build_object(
        'line',v_line_idx,'check','V1_action_case',
        'message',format('Invalid action "%s". Must be one of: Refill, Add New, Remove, Machine To Warehouse', v_action),
        'machine',v_machine,'product',v_product);
    END IF;

    IF v_qty IS NULL OR v_qty <= 0 THEN
      v_errors := v_errors || jsonb_build_object(
        'line',v_line_idx,'check','V2_quantity',
        'message',format('Quantity must be > 0, got %s', v_qty),
        'machine',v_machine,'product',v_product);
    END IF;

    IF v_action != 'Machine To Warehouse' THEN
      IF v_shelf IS NULL OR v_shelf !~ '^[A-Z]\d{2}$' THEN
        v_errors := v_errors || jsonb_build_object(
          'line',v_line_idx,'check','V3_shelf_code',
          'message',format('Invalid shelf_code "%s". Must match [A-Z][0-9][0-9] (e.g. A01, B12)', v_shelf),
          'machine',v_machine,'product',v_product);
      END IF;
    END IF;

    IF v_machine IS NULL OR NOT EXISTS (
      SELECT 1 FROM public.machines WHERE official_name = v_machine
    ) THEN
      v_errors := v_errors || jsonb_build_object(
        'line',v_line_idx,'check','V4_machine_name',
        'message',format('Unknown machine_name "%s"', v_machine),
        'product',v_product);
    END IF;

    IF v_product IS NULL OR NOT EXISTS (
      SELECT 1 FROM public.boonz_products WHERE boonz_product_name = v_product
    ) THEN
      v_errors := v_errors || jsonb_build_object(
        'line',v_line_idx,'check','V5_product_name',
        'message',format('Unknown boonz_product_name "%s"', v_product),
        'machine',v_machine);
    END IF;

    IF v_action != 'Machine To Warehouse' THEN
      v_dup_key := v_machine || '::' || v_shelf || '::' || v_product;
      IF v_dup_key = ANY(v_seen_keys) THEN
        v_errors := v_errors || jsonb_build_object(
          'line',v_line_idx,'check','V6_duplicate',
          'message',format('Duplicate row for %s / %s / %s in same batch', v_machine, v_shelf, v_product));
      ELSE
        v_seen_keys := array_append(v_seen_keys, v_dup_key);
      END IF;
    END IF;
  END LOOP;

  IF jsonb_array_length(v_errors) > 0 THEN
    RETURN jsonb_build_object(
      'status','validation_error',
      'plan_date',p_plan_date,
      'lines_submitted',v_line_idx,
      'errors_found',jsonb_array_length(v_errors),
      'errors',v_errors
    );
  END IF;

  SELECT ARRAY(
    SELECT DISTINCT r->>'machine_name'
    FROM jsonb_array_elements(p_lines) r
    WHERE r->>'machine_name' IS NOT NULL
  ) INTO v_machine_names;

  -- P0 FIX3: only delete a pending row when the incoming payload contains a
  -- replacement line for the same machine + same canonical shelf_code (A1 == A01).
  -- Machine To Warehouse lines with empty/null shelf_code match pending rows of
  -- that machine with the same action and empty/null shelf_code.
  DELETE FROM refill_plan_output t
  WHERE t.plan_date = p_plan_date
    AND t.operator_status = 'pending'
    AND t.machine_name = ANY(v_machine_names)
    AND EXISTS (
      SELECT 1
      FROM jsonb_array_elements(p_lines) r
      WHERE r->>'machine_name' = t.machine_name
        AND (
          (
            NULLIF(r->>'shelf_code','') IS NOT NULL
            AND NULLIF(t.shelf_code,'') IS NOT NULL
            AND regexp_replace(r->>'shelf_code', '^([A-Z])([0-9])$', '\1' || '0' || '\2')
              = regexp_replace(t.shelf_code, '^([A-Z])([0-9])$', '\1' || '0' || '\2')
          )
          OR
          (
            upper(r->>'action') = 'MACHINE TO WAREHOUSE'
            AND NULLIF(r->>'shelf_code','') IS NULL
            AND upper(t.action) = 'MACHINE TO WAREHOUSE'
            AND NULLIF(t.shelf_code,'') IS NULL
          )
        )
    );

  SELECT count(*) INTO v_stale_pending
  FROM refill_plan_output
  WHERE plan_date = p_plan_date
    AND operator_status = 'pending'
    AND machine_name = ANY(v_machine_names);

  IF v_stale_pending > 0 THEN
    INSERT INTO public.monitoring_alerts(source,severity,payload)
    VALUES ('write_refill_plan','warning', jsonb_build_object(
      'title', format('write_refill_plan %s: %s pending row(s) had NO replacement line in payload and were PRESERVED (was: silent delete)', p_plan_date, v_stale_pending),
      'plan_date', p_plan_date,
      'machines', to_jsonb(v_machine_names),
      'detected_at', now()
    ));
  END IF;

  v_line_idx := 0;
  FOR line IN SELECT * FROM jsonb_array_elements(p_lines)
  LOOP
    -- PRD-CLEAN-05 g8: populate the UUID key columns from the validated names
    -- (single source: machines / shelf_configurations / pod_products / boonz_products)
    INSERT INTO refill_plan_output (
      plan_date, machine_name, machine_priority, shelf_code,
      pod_product_name, boonz_product_name, action, quantity,
      current_stock, max_stock, smart_target, tier, global_score,
      fill_pct, comment, operator_status,
      machine_id, shelf_id, pod_product_id, boonz_product_id,
      source_origin, from_machine_id
    ) VALUES (
      p_plan_date,
      line->>'machine_name',
      COALESCE((line->>'machine_priority')::int, 0),
      line->>'shelf_code',
      line->>'pod_product_name',
      line->>'boonz_product_name',
      COALESCE(line->>'action', 'Refill'),
      (line->>'quantity')::int,
      (line->>'current_stock')::int,
      (line->>'max_stock')::int,
      (line->>'smart_target')::int,
      line->>'tier',
      (line->>'global_score')::numeric,
      (line->>'fill_pct')::numeric,
      line->>'comment',
      'pending',
      (SELECT m.machine_id FROM public.machines m WHERE m.official_name = line->>'machine_name' LIMIT 1),
      (SELECT sc.shelf_id FROM public.shelf_configurations sc
        JOIN public.machines m2 ON m2.machine_id = sc.machine_id AND m2.official_name = line->>'machine_name'
        WHERE sc.shelf_code = regexp_replace(line->>'shelf_code', '^([A-Z])([0-9])$', '\1' || '0' || '\2')
        LIMIT 1),
      (SELECT pp.pod_product_id FROM public.pod_products pp
        WHERE lower(trim(pp.pod_product_name)) = lower(trim(line->>'pod_product_name')) LIMIT 1),
      (SELECT bp.product_id FROM public.boonz_products bp
        WHERE lower(trim(bp.boonz_product_name)) = lower(trim(line->>'boonz_product_name')) LIMIT 1),
      COALESCE(NULLIF(line->>'source_origin','')::public.source_origin_enum, 'warehouse'::public.source_origin_enum),
      NULLIF(line->>'from_machine_id','')::uuid
    );
    v_count := v_count + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'status', 'ok',
    'plan_date', p_plan_date,
    'lines_written', v_count,
    'machines_affected', v_machine_names,
    'preflight_version', 'g8_id_keyed'
  ) || jsonb_build_object('stale_pending_preserved', v_stale_pending);
END;
$function$
